// ═══════════════════════════════════════════════════════════════════
// BANCO DE PREGUNTAS — DWES 
// Desarrollo Web en Entorno Servidor
// ═══════════════════════════════════════════════════════════════════

const BANCO = {

  // ─────────────────────────────────────────────────────────
  // UF1 — INTRODUCCIÓN AL LADO SERVIDOR
  // ─────────────────────────────────────────────────────────
  UF1: [
    { tema:'UF1', p:'¿Qué función PHP muestra información sobre la configuración del servidor y la versión de PHP instalada?', ops:['php_info()','server_info()','phpinfo()','getconfig()'], r:2, e:'phpinfo() muestra una página con toda la información de configuración de PHP, extensiones cargadas, variables de entorno y directivas php.ini.' },
    { tema:'UF1', p:'¿Qué archivo de configuración principal usa PHP para establecer sus directivas?', ops:['php.conf','httpd.ini','php.ini','server.cfg'], r:2, e:'php.ini es el archivo de configuración principal de PHP donde se definen directivas como max_execution_time, upload_max_filesize, display_errors, etc.' },
    { tema:'UF1', p:'¿Qué significa el modelo cliente-servidor en aplicaciones web?', ops:['El cliente y el servidor ejecutan el mismo código','El servidor está a la espera de peticiones de clientes para servirles recursos','El cliente almacena todos los datos de la aplicación','El servidor solo gestiona bases de datos'], r:1, e:'En el modelo cliente-servidor el servidor permanece en escucha de peticiones de clientes. El cliente solicita recursos y el servidor los busca y sirve.' },
    { tema:'UF1', p:'¿En qué se diferencia el procesamiento en el servidor del procesamiento en el cliente?', ops:['No hay diferencia, ambos ejecutan el mismo código','El servidor ejecuta código (PHP, Java...) antes de enviar el HTML al cliente; el cliente ejecuta JavaScript en el navegador','El cliente es más potente que el servidor siempre','El servidor solo sirve archivos estáticos, nunca procesa'], r:1, e:'El servidor ejecuta lenguajes de servidor (PHP, Java, Python...) antes de enviar la respuesta HTML al cliente. El cliente ejecuta JavaScript en el navegador.' },
    { tema:'UF1', p:'¿Qué stack tecnológico es libre y usa Apache, MySQL y PHP?', ops:['WISA','MEAN','LAMP','MERN'], r:2, e:'LAMP = Linux + Apache + MySQL + PHP. Es el stack libre más clásico para desarrollo web en entorno servidor.' },
    { tema:'UF1', p:'¿Cuál es el stack equivalente propietario al LAMP?', ops:['WISA','MEAN','MAMP','LEMP'], r:0, e:'WISA = Windows + IIS + SQL Server + ASP. Es el equivalente propietario de Microsoft al stack LAMP libre.' },
    { tema:'UF1', p:'¿Qué extensión tienen los archivos de código PHP?', ops:['.html','.php','.asp','.jsp'], r:1, e:'Los archivos PHP tienen extensión .php. El servidor web los procesa antes de enviar el resultado HTML al navegador del cliente.' },
    { tema:'UF1', p:'¿Qué hace la directiva "display_errors" en php.ini?', ops:['Activa o desactiva la visualización de errores PHP en el navegador','Establece el tamaño máximo de los archivos subidos','Define el tiempo máximo de ejecución de un script','Configura la conexión a la base de datos'], r:0, e:'display_errors controla si los errores de PHP se muestran en el navegador. Debe estar Off en producción y On en desarrollo.' },
    { tema:'UF1', p:'¿Cuál es el archivo de configuración de PHP?', ops:['myphp.ini','php.ini','myphp.conf','php.conf'], r:1, e:'php.ini es el archivo de configuración principal de PHP donde se definen todas las directivas del intérprete.' },
    { tema:'UF1', p:'¿Qué alias utilizamos para probar nuestros programas PHP en local?', ops:['localweb','localhost','hostweb','hostname'], r:1, e:'localhost (127.0.0.1) es el alias estándar que apunta al propio equipo, usado para probar aplicaciones web localmente.' },
    { tema:'UF1', p:'¿Cuál es el propósito del lado servidor en una aplicación web?', ops:['Controlar la interacción del usuario con la página','Determinar el diseño y la estructura visual del sitio','Procesar y gestionar los datos de la aplicación','Manejar la interfaz de usuario'], r:2, e:'El servidor procesa la lógica de negocio, accede a bases de datos y genera la respuesta HTML que se envía al cliente.' },
    { tema:'UF1', p:'¿Qué tecnologías se desarrollan en el lado cliente de una aplicación web?', ops:['UX/UI','Java','HTML5 y CSS3','Todas son correctas'], r:2, e:'El lado cliente se construye principalmente con HTML5, CSS3 y JavaScript. Son los lenguajes que interpreta el navegador.' },
    { tema:'UF1', p:'¿Cuál es la arquitectura con más capas de las aplicaciones web?', ops:['De una: la aplicación web','De dos: frontal y dashboard','De tres: el frontend, el backend y la base de datos','De cuatro: web cliente, dashboard, SGBDR y criptomonedas'], r:2, e:'La arquitectura de tres capas (frontend, backend y base de datos) es la más habitual y completa en aplicaciones web modernas.' },
    { tema:'UF1', p:'¿A partir de qué etapa de la web existe comunicación distribuida?', ops:['Web 1.0','Web 1.5','Web 2.0','Web3'], r:3, e:'La comunicación distribuida y la descentralización se asocian con Web3, que incorpora tecnologías como blockchain.' },
    { tema:'UF1', p:'¿Qué versión de HTML da fin a la Web 2.0?', ops:['HTML 2','HTML 3','HTML 4','HTML 5'], r:3, e:'HTML5 marcó el inicio de la Web moderna y el declive de la era Web 2.0, aportando nuevas APIs, multimedia nativa y semántica mejorada.' },
    { tema:'UF1', p:'¿Qué protocolos utiliza la arquitectura cliente-servidor?', ops:['TCP/IP','ARP y RARP','Cliente-servidor','No utiliza protocolos'], r:0, e:'La arquitectura cliente-servidor se basa en TCP/IP como protocolo de red, sobre el que se construye HTTP/HTTPS.' },
    { tema:'UF1', p:'¿Qué lenguaje de servidor se puede utilizar en desarrollos web? (opción más completa)', ops:['Solo PHP','PHP, Java EE y C son opciones válidas','Solo Java EE','Solo Python'], r:1, e:'En el servidor se pueden usar múltiples lenguajes: PHP, Java EE, Python, Node.js, Ruby, C#, etc.' },
    { tema:'UF1', p:'¿Qué SGBD instala el metapaquete lamp-server^?', ops:['Oracle Database','IBM DB2','MySQL','Microsoft SQL Server'], r:2, e:'El metapaquete lamp-server^ en sistemas Debian/Ubuntu instala Apache, MySQL y PHP (el stack LAMP completo).' },
    { tema:'UF1', p:'¿En qué etapa se comenzaron a utilizar páginas web dinámicas?', ops:['Web 1.0','Web 1.5','Web 2.0','Web3'], r:1, e:'Las páginas dinámicas (generadas por el servidor con PHP, ASP, etc.) surgieron en la etapa Web 1.5, como transición entre la web estática y la participativa.' },
    { tema:'UF1', p:'¿Para qué sirve la función ini_set() de PHP?', ops:['Para modificar las variables de configuración de PHP en tiempo de ejecución','Para cerrar una sesión','Para iniciar una sesión','Para leer el archivo php.ini'], r:0, e:'ini_set() permite modificar en tiempo de ejecución las directivas del archivo php.ini, sin necesidad de reiniciar el servidor.' },
    { tema:'UF1', p:'¿Cuál de los siguientes es un SGBD ampliamente utilizado en entornos web?', ops:['IBM DB2','MySQL','Oracle Database','Microsoft SQL Server'], r:1, e:'MySQL es el sistema de gestión de bases de datos relacionales más extendido en entornos web de código abierto.' },
    { tema:'UF1', p:'¿Qué tecnología usaban los servidores en la Web 1.0 para ejecutar programas que respondían a peticiones concretas?', ops:['PHP embebido','Servlets de Java','CGI (Common Gateway Interface)','ASP clásico'], r:2, e:'CGI (Common Gateway Interface) fue la primera tecnología de servidor para generar respuestas dinámicas. Podía estar hecho en C u otros lenguajes.' },
    { tema:'UF1', p:'¿Cuántos registros regionales de Internet (RIR) existen en el mundo?', ops:['3','4','5','6'], r:2, e:'Existen 5 RIR: RIPE NCC (Europa), ARIN (América del Norte), APNIC (Asia-Pacífico), AFRINIC (África) y LACNIC (Latinoamérica y Caribe).' },
    { tema:'UF1', p:'¿Qué puerto utiliza por defecto el protocolo DNS?', ops:['80','443','53','21'], r:2, e:'DNS escucha en el puerto 53, tanto por TCP como por UDP, para resolver nombres de dominio a direcciones IP.' },
    { tema:'UF1', p:'¿Cuál es la diferencia principal entre GET y POST al enviar datos de un formulario?', ops:['GET es más seguro que POST','GET añade los datos visibles en la URL; POST los envía en el cuerpo de la petición','POST no puede enviar imágenes','GET puede enviar más datos que POST'], r:1, e:'GET añade pares variable=valor a la URL (visible, limitado en tamaño). POST envía los datos en el cuerpo HTTP (discreto, sin límite práctico, puede incluir archivos).' },
    { tema:'UF1', p:'¿Qué significan las siglas RIA en el contexto de la Web 2.0?', ops:['Remote Internet Application','Rich Internet Application','Reactive Interface Architecture','Responsive Internet API'], r:1, e:'RIA = Rich Internet Application. Son apps web interactivas, multimedia y fluidas, típicas de la era Web 2.0.' },
    { tema:'UF1', p:'¿Qué IDE libre recomienda el temario UAX para programar PHP?', ops:['Eclipse','NetBeans','Visual Studio Code (VSC)','PhpStorm'], r:2, e:'Visual Studio Code (VSC) de Microsoft es el IDE libre recomendado. Es extensible a PHP, admite IntelliSense, terminal integrada y control de versiones.' },
    { tema:'UF1', p:'¿Cuál es la ruta de la carpeta donde Apache sirve las páginas web en XAMPP (Windows)?', ops:['C:\\xampp\\www','C:\\xampp\\apache\\html','C:\\xampp\\htdocs','C:\\xampp\\public'], r:2, e:'En XAMPP para Windows la carpeta raíz del servidor web Apache es C:\\xampp\\htdocs. Las páginas .php deben colocarse ahí.' },
    { tema:'UF1', p:'¿Qué es el protocolo HTTP?', ops:['Un lenguaje de programación de servidor','Un protocolo de comunicación sin estado para transferir recursos web entre cliente y servidor','Un sistema de gestión de bases de datos','Un protocolo de cifrado para comunicaciones seguras'], r:1, e:'HTTP (HyperText Transfer Protocol) es el protocolo base de la web. Es sin estado: cada petición es independiente. Funciona sobre TCP, normalmente en el puerto 80.' },
    { tema:'UF1', p:'¿Qué es Node.js y en qué se diferencia de PHP?', ops:['Un framework PHP moderno','Un entorno de ejecución de JavaScript en el servidor, basado en el motor V8 de Chrome y orientado a eventos','Un servidor web alternativo a Apache','Un gestor de paquetes para PHP'], r:1, e:'Node.js ejecuta JavaScript fuera del navegador. Es asíncrono y orientado a eventos, ideal para apps en tiempo real. PHP es síncrono y genera HTML en el servidor.' },
    { tema:'UF1', p:'¿Qué es el protocolo HTTPS y en qué se diferencia de HTTP?', ops:['HTTPS usa el puerto 8080; HTTP usa el 80','HTTPS cifra la comunicación mediante TLS/SSL; HTTP envía los datos en texto plano','HTTPS es más lento y solo para e-commerce','HTTPS solo funciona con certificados de pago'], r:1, e:'HTTPS añade una capa TLS/SSL que cifra la comunicación. Es imprescindible para proteger datos sensibles y es factor de posicionamiento SEO.' },
    { tema:'UF1', p:'¿Qué significa stateless aplicado al protocolo HTTP?', ops:['Que el servidor no guarda estado entre peticiones: cada petición es independiente y el servidor no recuerda la anterior','Que el servidor tiene muy poca memoria RAM','Que las páginas no usan CSS ni JavaScript','Que solo admite peticiones GET'], r:0, e:'HTTP es sin estado por diseño. Para mantener estado entre peticiones se usan cookies, sesiones, tokens JWT o parámetros en la URL.' },
    { tema:'UF1', p:'¿Cuáles son los métodos HTTP principales?', ops:['Solo GET y POST','GET, POST, PUT, DELETE, PATCH, HEAD y OPTIONS','Solo GET, POST y DELETE','GET, POST y REDIRECT'], r:1, e:'GET (leer), POST (crear), PUT (actualizar completo), DELETE (eliminar), PATCH (actualizar parcial). HEAD devuelve cabeceras sin cuerpo. OPTIONS lista los métodos permitidos.' },
    { tema:'UF1', p:'¿Qué son los códigos de estado HTTP?', ops:['Contraseñas de acceso al servidor','Números de tres dígitos que indican el resultado de una petición HTTP (2xx éxito, 3xx redirección, 4xx error cliente, 5xx error servidor)','Identificadores de sesión','Versiones del protocolo HTTP'], r:1, e:'Códigos clave: 200 OK, 201 Created, 301 Moved Permanently, 400 Bad Request, 401 Unauthorized, 403 Forbidden, 404 Not Found, 500 Internal Server Error.' },
    { tema:'UF1', p:'¿Qué es Docker en el contexto del desarrollo web?', ops:['Un servidor web moderno','Una plataforma de contenedores que empaqueta aplicaciones con todas sus dependencias para que funcionen igual en cualquier entorno','Un sistema de control de versiones','Un framework PHP para microservicios'], r:1, e:'Docker permite empaquetar una app y sus dependencias en un contenedor portable. docker-compose.yml define el entorno completo (PHP, MySQL, Nginx).' },
    { tema:'UF1', p:'¿Qué es un ORM y para qué sirve?', ops:['Un servidor de bases de datos orientado a objetos','Una capa de software que mapea tablas de BD relacional a clases y objetos del lenguaje, abstrayendo el SQL','Un formato de respuesta de APIs','Un protocolo de autenticación'], r:1, e:'ORM (Object-Relational Mapping): en lugar de SQL, se trabaja con objetos. User::find(1) en lugar de SELECT * FROM users WHERE id=1. Eloquent (Laravel) y Doctrine (Symfony) son ORMs PHP.' },
    { tema:'UF1', p:'¿Qué es Git y para qué se usa en proyectos web?', ops:['Un gestor de paquetes PHP','Un sistema de control de versiones distribuido que rastrea cambios en el código y permite colaboración en equipo','Un servidor web de alta disponibilidad','Un sistema de testing automatizado'], r:1, e:'Git registra el historial de cambios del código. Permite volver a versiones anteriores, trabajar en ramas y fusionar cambios de varios desarrolladores. GitHub/GitLab son plataformas de alojamiento.' },
    { tema:'UF1', p:'¿Qué es la inyección SQL y cómo se previene?', ops:['Un error de PHP al conectar con MySQL','Un ataque que inserta SQL malicioso en inputs del usuario para manipular la base de datos. Se previene con sentencias preparadas PDO.','Un método de optimización de consultas','Una técnica de indexación de bases de datos'], r:1, e:'SQL Injection: el atacante escribe SQL en un formulario para saltarse autenticación o extraer datos. Solución: usar PDO con sentencias preparadas ($pdo->prepare(); $stmt->execute([$input])).' },
    { tema:'UF1', p:'¿Qué es el patrón de diseño MVC?', ops:['Model-View-Controller: separa datos (Model), presentación (View) y lógica de control (Controller) para organizar el código','Motor-Vista-CSS: nomenclatura de estilos en frameworks','Multiple-Version-Control: sistema de ramas en Git','Machine-Virtual-Cloud: arquitectura de despliegue'], r:0, e:'MVC es el patrón base de frameworks como Laravel y Symfony. El Controlador recibe la petición, el Modelo accede a datos y la Vista renderiza la respuesta HTML.' },
  ],

  // ─────────────────────────────────────────────────────────
  // UF2 — PHP BÁSICO
  // ─────────────────────────────────────────────────────────
  UF2: [
    { tema:'UF2', p:'¿Cuál es la diferencia entre comillas dobles y comillas simples para definir strings en PHP?', ops:['No hay ninguna diferencia','Las dobles permiten interpolar variables y secuencias de escape; las simples no','Las simples permiten interpolar variables; las dobles no','Las dobles solo sirven para HTML'], r:1, e:'Con comillas dobles, PHP interpola variables ($var) y secuencias de escape (\\n, \\t). Con comillas simples, el texto es literal.' },
    { tema:'UF2', p:'¿Qué es la sintaxis heredoc en PHP?', ops:['Un tipo de array multidimensional','Una forma de escribir strings de varias líneas equivalente a entrecomillado doble, sin necesitar escapar comillas','Una directiva de configuración de Apache','Una variante de require_once'], r:1, e:'heredoc (<<<EOD ... EOD;) es equivalente a entrecomillado doble pero sin necesitar escapar comillas. Permite incluir HTML y variables sin conflictos.' },
    { tema:'UF2', p:'¿Qué función PHP convierte los saltos de línea \\n en etiquetas HTML br?', ops:['nl2html()','linebreak()','nl2br()','str_nl()'], r:2, e:'nl2br() inserta un salto de línea HTML (&lt;br&gt;) antes de cada \\n en la cadena. Es útil para mostrar texto multilínea en el navegador.' },
    { tema:'UF2', p:'¿Qué operador se usa en PHP para elevar un número a una potencia?', ops:['%','//','**','^'], r:2, e:'El operador ** es la potenciación en PHP. Por ejemplo, $c = 2**3 devuelve 8.' },
    { tema:'UF2', p:'¿Qué operador lógico en PHP devuelve true solo si TODAS las expresiones son verdaderas?', ops:['||','!','&&','xor'], r:2, e:'"&&" (and) devuelve true cuando todas las expresiones evaluadas son verdaderas. "||" (or) devuelve true si al menos una lo es.' },
    { tema:'UF2', p:'¿Qué diferencia principal existe entre === y == en PHP?', ops:['No hay diferencia','=== compara valor y tipo; == solo compara valor','== es más estricto que ===','=== solo funciona con enteros'], r:1, e:'== compara valores (con conversión de tipos implícita). === es comparación idéntica: mismo valor Y mismo tipo. "5" == 5 es true, pero "5" === 5 es false.' },
    { tema:'UF2', p:'¿Qué función PHP obtiene el tipo de dato de una variable?', ops:['typeof()','var_type()','gettype()','is_type()'], r:2, e:'gettype() devuelve una cadena con el tipo PHP de la variable: "string", "integer", "float", "boolean", "array", "object", "NULL".' },
    { tema:'UF2', p:'¿Qué constante predefinida de PHP contiene el valor matemático de π?', ops:['PI','MATH_PI','M_PI','PHP_PI'], r:2, e:'M_PI es la constante predefinida de PHP con el valor de π (3.14159...). No hace falta usar define() para definirla.' },
    { tema:'UF2', p:'¿En qué orden se pasan los parámetros a mktime() en PHP?', ops:['día, mes, año','año, mes, día','hora, minutos, segundos, mes, día, año','año, mes, día, hora, minutos, segundos'], r:2, e:'mktime(hora, min, seg, mes, día, año) genera un timestamp Unix. Se puede pasar como segundo argumento a date() para formatear fechas específicas.' },
    { tema:'UF2', p:'¿Qué función PHP calcula la diferencia entre dos objetos DateTime?', ops:['date_sub()','date_diff()','datetime_diff()','mktime_diff()'], r:1, e:'date_diff($fecha1, $fecha2) devuelve un objeto DateInterval con la diferencia. Se usa format("%a") para obtener la diferencia en días totales.' },
    { tema:'UF2', p:'¿Qué diferencia hay entre while y do…while en PHP?', ops:['No hay diferencia','while evalúa la condición antes; do…while la evalúa después, ejecutándose siempre al menos una vez','do…while es más eficiente que while','while se usa solo con arrays'], r:1, e:'while evalúa antes: si es false desde el inicio, el bloque no se ejecuta. do…while evalúa al final, garantizando al menos una ejecución.' },
    { tema:'UF2', p:'¿Para qué sirve la instrucción continue dentro de un bucle PHP?', ops:['Detiene el bucle completamente','Salta a la siguiente iteración sin ejecutar el resto del cuerpo del bucle actual','Reinicia el bucle desde el principio','Es sinónimo de break'], r:1, e:'continue fuerza el salto a la siguiente iteración del bucle, omitiendo el código restante de la iteración actual. break sale del bucle completamente.' },
    { tema:'UF2', p:'¿Qué hace foreach($array as $clave => $valor) en PHP?', ops:['Itera solo por los valores, ignorando las claves','Itera el array asignando a $clave el índice y a $valor el contenido de cada posición','Ordena el array por clave','Solo funciona con arrays asociativos'], r:1, e:'foreach($arr as $k=>$v) itera por todos los elementos asignando la clave a $k y el valor a $v.' },
    { tema:'UF2', p:'¿Qué función PHP permite reindexar un array para eliminar huecos producidos por unset()?', ops:['array_reset()','array_reindex()','array_values()','sort()'], r:2, e:'array_values() devuelve un nuevo array con los mismos valores pero con índices numéricos consecutivos desde 0, eliminando huecos.' },
    { tema:'UF2', p:'¿Qué hace implode() en PHP?', ops:['Divide una cadena en un array usando un separador','Une los elementos de un array en una cadena usando un separador','Elimina elementos duplicados de un array','Convierte un array a JSON'], r:1, e:'implode(separador, array) une los elementos del array en una sola cadena, insertando el separador entre cada par de elementos. Es el inverso de explode().' },
    { tema:'UF2', p:'¿Qué diferencia hay entre include y require en PHP cuando el archivo NO existe?', ops:['Ambos dan error fatal y detienen el script','include da un warning y continúa; require da un error fatal y detiene el script','require da un warning; include da un fatal','Ambos simplemente ignoran el archivo faltante'], r:1, e:'include emite E_WARNING y continúa la ejecución. require emite E_ERROR (fatal) y detiene el script. Por eso require se usa cuando el archivo es imprescindible.' },
    { tema:'UF2', p:'¿Cuándo es preferible usar include_once o require_once frente a include/require?', ops:['Siempre, porque son más rápidos','Cuando el archivo puede haberse incluido ya en otro punto del código, para evitar doble inclusión y redefinición de funciones','Solo con archivos PHP externos de terceros','Solo en proyectos pequeños'], r:1, e:'_once verifica si el archivo ya fue incluido. Es útil en proyectos grandes con muchas inclusiones, evitando errores de redefinición.' },
    { tema:'UF2', p:'¿Qué función PHP permite saber cuántos parámetros ha recibido una función cuando se declara sin parámetros fijos?', ops:['count_args()','func_num_args()','params_count()','arg_count()'], r:1, e:'func_num_args() devuelve el número de argumentos pasados a la función. Se usa junto a func_get_arg($i) para acceder a cada argumento individualmente.' },
    { tema:'UF2', p:'¿Qué hace el operador ... (spread) en la firma de una función PHP?', ops:['Indica que la función no acepta parámetros','Permite pasar un número variable de argumentos que se recogen en un array','Es la sintaxis para pasar por referencia','Es el operador de concatenación de PHP 8'], r:1, e:'function suma(...$nums) recoge todos los argumentos en el array $nums. Es la forma moderna de funciones con aridad variable.' },
    { tema:'UF2', p:'¿Qué modificador hay que añadir a un parámetro para pasarlo por referencia en PHP?', ops:['*','->','&','@'], r:2, e:'El símbolo & antes del nombre del parámetro (function f(&$var)) hace que la función trabaje sobre la variable original.' },
    { tema:'UF2', p:'¿Qué función PHP divide una cadena en un array usando un separador?', ops:['str_split()','explode()','chunk_split()','preg_split() únicamente'], r:1, e:'explode($sep, $str) divide una cadena en un array usando el separador indicado. implode() hace la operación inversa: une un array en una cadena.' },
    { tema:'UF2', p:'¿Qué función PHP ordena un array manteniendo la asociación entre clave y valor?', ops:['sort()','asort()','ksort()','rsort()'], r:1, e:'asort() ordena los valores del array manteniendo la correspondencia clave→valor. sort() reindexaría. ksort() ordena por claves. arsort() ordena valores descendentemente.' },
    { tema:'UF2', p:'¿Qué función PHP genera un número entero aleatorio entre dos valores?', ops:['random()','rand()','mt_rand()','Tanto rand() como mt_rand() son válidos'], r:3, e:'Tanto rand($min,$max) como mt_rand($min,$max) generan enteros aleatorios. mt_rand usa el algoritmo Mersenne Twister, más rápido y con mejor distribución estadística.' },
    { tema:'UF2', p:'¿Cuál es la diferencia entre include y require en PHP?', ops:['No hay diferencia','require genera un error fatal si el archivo no existe; include solo una advertencia','include genera un error fatal; require solo una advertencia','require solo funciona con archivos .php'], r:1, e:'require detiene la ejecución con E_COMPILE_ERROR si el archivo no existe. include solo emite E_WARNING y continúa. require_once e include_once evitan incluir el mismo archivo varias veces.' },
    { tema:'UF2', p:'¿Qué función PHP convierte una cadena en mayúsculas?', ops:['upper()','str_upper()','strtoupper()','toUpper()'], r:2, e:'strtoupper() convierte toda la cadena a mayúsculas. strtolower() a minúsculas. ucfirst() solo la primera letra. ucwords() la primera de cada palabra.' },
    { tema:'UF2', p:'¿Qué hace la función PHP array_merge()?', ops:['Ordena dos arrays y los combina','Une dos o más arrays en uno, añadiendo los elementos del segundo al final del primero','Intersecciona dos arrays devolviendo los elementos comunes','Elimina los elementos duplicados de un array'], r:1, e:'array_merge($a, $b) devuelve un nuevo array con todos los elementos de $a seguidos de los de $b. Para arrays asociativos, las claves del segundo sobreescriben las del primero si coinciden.' },
    { tema:'UF2', p:'¿Cómo se accede a un elemento de un array asociativo en PHP?', ops:['$array->clave','$array["clave"] o $array[\'clave\']','$array.clave','$array(clave)'], r:1, e:'En arrays asociativos PHP se accede por clave entre corchetes: $array["clave"] o $array[\'clave\']. Los arrays numéricos se acceden por índice: $array[0].' },
    { tema:'UF2', p:'¿Qué hace la función PHP count()?', ops:['Cuenta los caracteres de una cadena','Devuelve el número de elementos de un array','Cuenta las líneas de un archivo de texto','Cuenta las ocurrencias de un valor en un array'], r:1, e:'count($array) devuelve el número de elementos. Para cadenas se usa strlen(). count($array, COUNT_RECURSIVE) cuenta también los elementos de arrays anidados.' },
    { tema:'UF2', p:'¿Qué es una función anónima (closure) en PHP?', ops:['Una función sin parámetros','Una función sin nombre que puede asignarse a una variable o pasarse como argumento','Una función que solo se ejecuta una vez','Una función que no retorna ningún valor'], r:1, e:'Los closures ($fn = function($x) { return $x*2; }) son funciones anónimas. Pueden capturar variables externas con use ($var). Son muy usadas como callbacks y en programación funcional.' },
    { tema:'UF2', p:'¿Qué operador PHP se usa para el operador ternario?', ops:['? :','if/else','&&','??'], r:0, e:'El operador ternario es $resultado = $condicion ? $si_true : $si_false. El operador ?? (null coalescing) devuelve el primer operando si no es null: $a ?? $b.' },
    { tema:'UF2', p:'¿Qué es la programación orientada a objetos (POO) en PHP?', ops:['Una técnica exclusiva de Java','Un paradigma que organiza el código en clases y objetos con atributos y métodos, favoreciendo la reutilización y el mantenimiento','Un tipo especial de arrays PHP','Una extensión PHP para trabajar con bases de datos'], r:1, e:'La POO agrupa datos (atributos) y comportamiento (métodos) en clases. Permite herencia, encapsulación y polimorfismo. PHP admite POO completa desde PHP 5.' },
    { tema:'UF2', p:'¿Qué es el alcance (scope) de una variable en PHP?', ops:['El tamaño máximo que puede tener una variable','El contexto en el que una variable es accesible: global, local (dentro de función) o estático','La precisión de las variables float','El número máximo de caracteres de un string'], r:1, e:'Las variables PHP tienen alcance local dentro de funciones. Para acceder a una global desde una función: global $var. Las variables static dentro de una función persisten entre llamadas.' },
    { tema:'UF2', p:'¿Qué hace la función PHP array_filter()?', ops:['Ordena un array por sus valores','Filtra los elementos de un array que cumplan la condición de la función callback','Elimina los elementos duplicados','Devuelve los primeros N elementos'], r:1, e:'array_filter($arr, $callback) devuelve un nuevo array con solo los elementos para los que $callback devuelve true. Sin callback, elimina los valores falsy (false, null, 0, "", []).' },
    { tema:'UF2', p:'¿Para qué sirve la función PHP array_map()?', ops:['Para ordenar un array aplicando una función de comparación','Para aplicar una función a cada elemento de un array y devolver el array transformado','Para buscar un elemento en un array','Para fusionar dos arrays'], r:1, e:'array_map($callback, $arr) aplica $callback a cada elemento y devuelve el array de resultados. array_map(fn($x) => $x*2, [1,2,3]) devuelve [2,4,6].' },
    { tema:'UF2', p:'¿Qué hace str_replace() en PHP?', ops:['Busca la primera ocurrencia y la reemplaza','Busca todas las ocurrencias de un string y las reemplaza por otro','Elimina todos los espacios de una cadena','Divide una cadena por un separador'], r:1, e:'str_replace($buscar, $reemplazar, $cadena) reemplaza todas las ocurrencias. str_ireplace hace lo mismo sin distinguir mayúsculas. Acepta arrays para múltiples reemplazos simultáneos.' },
    { tema:'UF2', p:'¿Qué devuelve PHP al evaluar: var_dump("5" + 3)?', ops:['Error de tipo','string(1) "8"','int(8)','float(8)'], r:2, e:'PHP convierte "5" (string) a entero y suma: 5+3=8. var_dump muestra el tipo: int(8). Con "5.5" + 3 el resultado sería float(8.5).' },
    { tema:'UF2', p:'¿Qué función PHP verifica si un valor existe en un array?', ops:['array_has()','in_array()','isset_array()','array_search() únicamente'], r:1, e:'in_array($valor, $array) devuelve true si el valor existe. array_search() devuelve la clave. Con tercer parámetro true hace comparación estricta (===).' },
    { tema:'UF2', p:'¿Qué es un array multidimensional en PHP?', ops:['Un array con más de 1000 elementos','Un array cuyos elementos son a su vez arrays, permitiendo estructuras como tablas o matrices','Un array ordenado de mayor a menor','Un array con claves de tipo string obligatoriamente'], r:1, e:'Los arrays multidimensionales tienen arrays como valores. $tabla[0]["nombre"] accede al campo nombre del primer elemento. Son útiles para representar resultados de bases de datos.' },
    { tema:'UF2', p:'¿Cuál es la diferencia entre echo y print en PHP?', ops:['Son idénticos en todo','echo puede imprimir múltiples valores separados por comas; print solo acepta uno y devuelve 1','print es para objetos; echo para tipos primitivos','echo devuelve 1; print devuelve void'], r:1, e:'echo y print producen el mismo output. echo acepta lista de parámetros (echo $a, $b). print devuelve 1 (puede usarse en expresiones). En la práctica, echo es lo más usado.' },
    { tema:'UF2', p:'¿Qué es la recursividad en PHP y cuándo se usa?', ops:['Una técnica para duplicar arrays','Una función que se llama a sí misma para resolver problemas divisibles en subproblemas del mismo tipo','Un tipo especial de bucle while','Un patrón para recorrer arrays asociativos'], r:1, e:'La recursividad es útil para estructuras jerárquicas (árboles, factorial, Fibonacci, recorrer directorios). Siempre necesita un caso base que detenga la recursión.' },
  ],

  // ─────────────────────────────────────────────────────────
  // UF3 — PHP AVANZADO
  // ─────────────────────────────────────────────────────────
  UF3: [
    { tema:'UF3', p:'¿Qué función se utiliza para redireccionar a un usuario a otra página en PHP?', ops:['forward()','header()','location()','redirect()'], r:1, e:'header("Location: url") redirige al usuario. Debe llamarse antes de cualquier salida HTML.' },
    { tema:'UF3', p:'¿Qué símbolo se utiliza para concatenar cadenas en PHP?', ops:['+',',','.','&'], r:2, e:'En PHP el operador de concatenación es el punto (.). Por ejemplo: "Hola" . " mundo" produce "Hola mundo".' },
    { tema:'UF3', p:'¿Cuál de las siguientes funciones se utiliza para obtener el último elemento de un array en PHP?', ops:['last()','end()','array_end()','array_last()'], r:1, e:'end() mueve el puntero interno al último elemento del array y devuelve su valor.' },
    { tema:'UF3', p:'¿Qué diferencia hay entre include y require si el fichero referenciado existe?', ops:['include carga el archivo cada vez mientras que require solo una','include da error, mientras que require no','Ninguna','require da error, mientras que include no'], r:2, e:'Cuando el fichero existe, include y require se comportan exactamente igual. La diferencia aparece si el fichero no existe.' },
    { tema:'UF3', p:'¿Qué función de PHP se utiliza para validar un DNI con expresiones regulares?', ops:['check_dni()','validate_dni()','preg_match()','regex_check()'], r:2, e:'preg_match() evalúa si una cadena coincide con un patrón de expresión regular. Es la función estándar de PHP para validaciones con regex.' },
    { tema:'UF3', p:'¿Qué patrón regex de PHP sirve para validar un DNI (8 dígitos + letra mayúscula)?', ops:['/^[9]{8}[A-Z]{1}$/','¿/^[0-9]{8}[A-Z]{1}$/?','/^[0-9]{8}[A-Z]{1}/','¿/^[a-z]{8}[0-9]{1}$/?'], r:1, e:'/^[0-9]{8}[A-Z]{1}$/ valida exactamente 8 dígitos seguidos de 1 letra mayúscula, de principio a fin de cadena.' },
    { tema:'UF3', p:'¿Cuál de estas estructuras de PHP permite implementar herencia múltiple?', ops:['includes','clases','traits','interfaces'], r:2, e:'Los traits permiten reutilizar conjuntos de métodos en clases independientes, simulando herencia múltiple en PHP.' },
    { tema:'UF3', p:'¿Qué modificador se usa para un atributo de clase con mismo valor para todos los objetos e inmutable?', ops:['private','static','const','protected'], r:2, e:'const define una constante de clase: compartida entre todos los objetos e inmutable. static es compartida pero modificable.' },
    { tema:'UF3', p:'¿Qué función de PHP se utiliza para configurar el tipo de errores que se desean mostrar?', ops:['error_exception()','error_reporting()','set_error()','display_errors()'], r:1, e:'error_reporting() establece qué tipos de errores (E_ALL, E_WARNING, E_NOTICE...) muestra PHP.' },
    { tema:'UF3', p:'¿Qué tipo de estructura de control se utiliza para capturar excepciones en PHP?', ops:['try','finally','catch','throw'], r:2, e:'catch captura la excepción lanzada en el bloque try. Se usa junto con try y opcionalmente finally.' },
    { tema:'UF3', p:'¿Cuál de los siguientes arrays NO sirve para leer directamente los datos de un formulario?', ops:['$_POST','$_GET','$_SESSION','$_REQUEST'], r:2, e:'$_SESSION almacena datos de sesión del usuario, no datos de formularios. $_POST y $_GET reciben datos de formularios.' },
    { tema:'UF3', p:'Si un formulario tiene un select con multiple activado, ¿cómo se reciben los datos en PHP?', ops:['Como un string','Como un número','Como un array','Como un objeto'], r:2, e:'Con el atributo multiple, el select envía varios valores. PHP los recibe como array si el name termina en [] (ej: lista[]).' },
    { tema:'UF3', p:'¿Cuándo devuelve true la función isset($variable) en PHP?', ops:['Cuando la variable tiene valor NULL','Cuando la variable no existe','Cuando la variable existe y tiene un valor distinto de NULL','Cuando la variable está vacía'], r:2, e:'isset() devuelve true si la variable existe Y su valor no es NULL. is_null() comprueba si es exactamente NULL.' },
    { tema:'UF3', p:'¿Qué debe hacerse para destruir completamente una sesión en PHP?', ops:['Usar solo session_destroy()','Usar solo session_unset()','Vaciar $_SESSION, llamar session_destroy() y borrar la cookie de sesión si existe','Cerrar el navegador del cliente'], r:2, e:'Para destruir una sesión completamente: $_SESSION = []; session_destroy(); y, si se usan cookies, borrar también la cookie de sesión.' },
    { tema:'UF3', p:'¿Qué función PHP crea o actualiza una cookie en el cliente?', ops:['cookie_set()','create_cookie()','setcookie()','setCookieHeader()'], r:2, e:'setcookie(nombre, valor, expiración, ...) crea la cookie en el cliente. Debe ejecutarse antes de cualquier salida HTML.' },
    { tema:'UF3', p:'¿Mediante qué superglobal se lee el valor de una cookie en PHP?', ops:['$_SESSION','$_COOKIE','$_GET','$_SERVER'], r:1, e:'$_COOKIE["nombre"] da acceso al valor de la cookie. Las cookies son enviadas por el navegador en cada petición HTTP.' },
    { tema:'UF3', p:'¿Qué hace la función session_start() en PHP?', ops:['Crea una cookie permanente','Inicia o reanuda la sesión actual; debe llamarse al principio de cada página que use sesiones','Destruye la sesión activa','Regenera el ID de sesión por seguridad'], r:1, e:'session_start() inicializa o retoma la sesión. Sin llamarla, el array $_SESSION no está disponible.' },
    { tema:'UF3', p:'HTTP es un protocolo sin estado. ¿Qué significa esto para las aplicaciones web?', ops:['Cada petición al servidor es una conexión nueva que no guarda información de conexiones anteriores','El servidor nunca recuerda al usuario','HTTP no puede transmitir datos entre páginas','El estado se guarda automáticamente en el servidor'], r:0, e:'HTTP no preserva estado entre peticiones. Cada petición es independiente. Para mantener estado se usan sesiones, cookies o tokens.' },
    { tema:'UF3', p:'¿Qué ataque de seguridad consiste en introducir código malicioso en un formulario para que se ejecute en el navegador de otros usuarios?', ops:['SQL Injection','CSRF','XSS (Cross-Site Scripting)','Fuerza bruta'], r:2, e:'XSS permite a un atacante inyectar scripts en páginas visitadas por otros usuarios. Se previene escapando la salida con htmlspecialchars().' },
    { tema:'UF3', p:'¿Qué función PHP se usa para escapar caracteres especiales HTML y prevenir XSS?', ops:['strip_tags()','html_escape()','htmlspecialchars()','sanitize()'], r:2, e:'htmlspecialchars() convierte &lt;, &gt;, &amp;, " y \' en sus entidades HTML. Es la defensa principal contra XSS al mostrar datos del usuario.' },
    { tema:'UF3', p:'¿Qué palabra clave en PHP lanza explícitamente una excepción?', ops:['catch','raise','throw','trigger'], r:2, e:'throw new Exception("mensaje") lanza una excepción que debe ser capturada por un bloque try-catch o provocará un error fatal.' },
    { tema:'UF3', p:'¿Qué diferencia hay entre una clase abstracta y una interfaz en PHP?', ops:['No hay diferencia','Una clase abstracta puede tener métodos con implementación; una interfaz solo define la firma de los métodos','Una interfaz puede tener propiedades; la clase abstracta no','Solo se puede usar una de las dos en el mismo proyecto'], r:1, e:'La clase abstracta puede tener métodos implementados y propiedades. La interfaz solo define contratos (firmas de métodos), sin implementación.' },
    { tema:'UF3', p:'¿Qué modificador de acceso hace que un atributo o método solo sea accesible desde la propia clase?', ops:['public','protected','private','static'], r:2, e:'private restringe el acceso al interior de la propia clase. protected permite el acceso también en clases hijas (herencia).' },
    { tema:'UF3', p:'¿Cómo se accede a un atributo de instancia dentro de un método de la misma clase en PHP?', ops:['self::$atributo','this->atributo','$this->atributo','self->$atributo'], r:2, e:'$this->atributo accede al atributo de la instancia actual. self:: se usa para atributos o métodos estáticos o constantes.' },
    { tema:'UF3', p:'¿Qué función PHP se usa para convertir un array a formato JSON?', ops:['json_decode()','array_to_json()','json_encode()','serialize()'], r:2, e:'json_encode($array) convierte un array PHP en una cadena JSON. json_decode() hace el proceso inverso.' },
    { tema:'UF3', p:'¿Qué atributo de la etiqueta form en HTML define la página receptora de los datos?', ops:['method','target','action','name'], r:2, e:'El atributo action indica la URL de destino a la que se enviarán los datos del formulario al pulsar el botón submit.' },
    { tema:'UF3', p:'¿Cómo se envían múltiples checkboxes con el mismo grupo al servidor para que PHP los reciba como array?', ops:['name="grupo" en todos','name="grupo[]" en todos','id="grupo" en todos','class="grupo" en todos'], r:1, e:'Al añadir [] al name (nombre[]), PHP recibe todos los valores marcados como un array asociativo.' },
    { tema:'UF3', p:'¿Qué hace la función empty() en PHP?', ops:['Elimina el contenido de una variable','Devuelve true si la variable tiene un valor vacío o nulo (incluyendo "", 0, false, null, [])','Comprueba si el array está vacío solo','Borra una variable del ámbito'], r:1, e:'empty() devuelve true para: "", 0, "0", null, false, [] y variables no definidas. Útil para validar formularios.' },
    { tema:'UF3', p:'¿Dónde DEBE situarse la instrucción header() con respecto a la salida HTML?', ops:['Después del body','Antes de cualquier salida HTML o de espacios en blanco','Dentro de la etiqueta head','Al final del script'], r:1, e:'header() debe llamarse ANTES de cualquier salida (incluso espacios). Si ya se envió algo, PHP genera un error "headers already sent".' },
    { tema:'UF3', p:'¿Qué clase permite capturar tanto errores (Error) como excepciones (Exception) en PHP 7+?', ops:['BaseException','ErrorException','Throwable','GenericError'], r:2, e:'Throwable es la interfaz base de PHP 7+ que engloba tanto Exception como Error. Capturando Throwable se procesan todos los errores.' },
    { tema:'UF3', p:'¿Qué método mágico de PHP se llama automáticamente al crear una instancia de una clase?', ops:['__start()','__init()','__construct()','__new()'], r:2, e:'__construct() es el método constructor de PHP. Se ejecuta automáticamente con new Clase(). __destruct() se llama al destruir el objeto.' },
    { tema:'UF3', p:'En herencia PHP, ¿qué palabra clave se usa para llamar al constructor de la clase padre?', ops:['parent::__construct()','super()','base::__construct()','extends::__construct()'], r:0, e:'parent::__construct() invoca el constructor de la clase padre desde el constructor de la clase hija.' },
    { tema:'UF3', p:'¿Para qué sirve el array $_REQUEST en PHP?', ops:['Solo para leer cookies','Solo para leer sesiones','Para acceder a datos de GET, POST y COOKIE indistintamente','Para leer cabeceras HTTP'], r:2, e:'$_REQUEST es una unión de $_GET, $_POST y $_COOKIE. Útil cuando no se sabe por qué método llegará la información.' },
    { tema:'UF3', p:'¿Qué es la inyección de dependencias en PHP?', ops:['Una vulnerabilidad de seguridad PHP','Un patrón donde las dependencias se pasan desde fuera en lugar de crearlas internamente, facilitando el testing y el desacoplamiento','Una función PHP para incluir archivos externos','Una técnica de optimización de consultas SQL'], r:1, e:'La inyección de dependencias (DI) pasa las dependencias como parámetros en lugar de crearlas dentro de la clase. Facilita el testing (se pueden usar mocks), reduce el acoplamiento y mejora la mantenibilidad.' },
    { tema:'UF3', p:'¿Qué son las interfaces en PHP?', ops:['Clases que no se pueden instanciar','Contratos que obligan a las clases que las implementan a definir ciertos métodos','Archivos de configuración de PHP','Módulos de extensión de PHP'], r:1, e:'Una interface define qué métodos debe tener una clase (sin implementación). Las clases que la implementan (implements) están obligadas a definir todos esos métodos. Permiten polimorfismo sin herencia.' },
    { tema:'UF3', p:'¿Qué es el patrón Singleton en PHP?', ops:['Un patrón que garantiza que una clase tiene solo una instancia y proporciona un punto de acceso global','Un patrón para crear colecciones de objetos similares','Un patrón para conectar bases de datos','Un patrón de herencia múltiple'], r:0, e:'Singleton garantiza que solo existe una instancia de la clase. Útil para conexiones BD o registros de configuración. Se implementa con constructor privado y método estático getInstance().' },
    { tema:'UF3', p:'¿Qué hace la función PHP file_get_contents()?', ops:['Crea un archivo nuevo con el contenido dado','Lee todo el contenido de un archivo (o URL) y lo devuelve como string','Lista los archivos de un directorio','Elimina el contenido de un archivo'], r:1, e:'file_get_contents($path) lee un archivo completo en un string. También puede hacer peticiones HTTP básicas. Para escribir: file_put_contents($path, $contenido). Para grandes archivos, usar fopen()/fread().' },
    { tema:'UF3', p:'¿Qué es un trait en PHP?', ops:['Un tipo especial de interfaz','Un mecanismo para reutilizar código entre clases que no tienen relación de herencia','Un alias para las clases abstractas','Un tipo de variable especial para valores booleanos'], r:1, e:'Los traits permiten reutilizar conjuntos de métodos en clases independientes (PHP no tiene herencia múltiple). Se insertan con use dentro de la clase. Solución al problema del diamante.' },
    { tema:'UF3', p:'¿Qué es el namespace en PHP y para qué sirve?', ops:['Un tipo especial de variable global','Un mecanismo para organizar clases en espacios de nombres, evitando conflictos entre clases con el mismo nombre de diferentes librerías','Una directiva de configuración de Apache','Un tipo de array asociativo'], r:1, e:'namespace permite agrupar clases bajo un espacio de nombres (namespace App\\Http\\Controllers). use permite importarlas. Esencial en proyectos grandes y al usar Composer con múltiples librerías.' },
    { tema:'UF3', p:'¿Qué es el autoloading PSR-4 en PHP?', ops:['Un sistema de caché de clases PHP','Un estándar que carga automáticamente los archivos de clase según la estructura de namespaces y directorios, sin require manual','Una extensión PHP para carga dinámica','Una directiva de php.ini'], r:1, e:'PSR-4: si el namespace App\\Models\\User mapea a src/Models/User.php, Composer lo cargará automáticamente. Composer genera vendor/autoload.php; solo hay que hacer require_once ese archivo.' },
  ],

  // ─────────────────────────────────────────────────────────
  // UF4 — ACCESO A DATOS (PDO, ficheros, XML, MongoDB)
  // ─────────────────────────────────────────────────────────
  UF4: [
    { tema:'UF4', p:'¿Qué función, aplicada a un fichero, devuelve la fecha y hora del último acceso?', ops:['filetime()','filemtime()','fileatime()','fileaccesstime()'], r:2, e:'fileatime() devuelve el timestamp Unix del último acceso al fichero. filemtime() devuelve la fecha de última modificación.' },
    { tema:'UF4', p:'¿Cuál es el comando correcto para ejecutar una sentencia SQL tipo SELECT con PDO?', ops:['$pdo->select($sql)','$pdo->query($sql)','$pdo->exec($sql)','$pdo->fetch($sql)'], r:1, e:'query() ejecuta una sentencia SQL y devuelve un PDOStatement. exec() se usa para INSERT/UPDATE/DELETE y devuelve filas afectadas.' },
    { tema:'UF4', p:'¿Para qué sirve el método rollback() de la clase PDO?', ops:['Para empezar una transacción','Para deshacer una transacción','Para finalizar una transacción con éxito','Para confirmar una transacción'], r:1, e:'rollback() deshace todos los cambios realizados desde el último beginTransaction(). commit() los confirma.' },
    { tema:'UF4', p:'¿Para qué sirve la función fflush() en PHP?', ops:['Para leer los datos de un fichero','Para cerrar el acceso a un fichero','Para volcar al fichero lo que quede en el buffer','Para abrir un fichero en modo escritura'], r:2, e:'fflush() fuerza la escritura del buffer interno al fichero en disco, sin esperar a que se cierre con fclose().' },
    { tema:'UF4', p:'¿Para qué sirve el método prepare() de la clase PDO?', ops:['Para ejecutar una sentencia preparada','Para crear una sentencia preparada','Para ejecutar una instrucción directamente','Para conectar con la base de datos'], r:1, e:'prepare() crea una sentencia preparada (PDOStatement) con marcadores (:param o ?). Después se ejecuta con execute().' },
    { tema:'UF4', p:'¿En qué unidad devuelve filesize() el tamaño de un fichero?', ops:['bytes','kilobytes','megabytes','gigabytes'], r:0, e:'filesize() devuelve el tamaño del fichero en bytes. Para KB dividir por 1024, para MB entre 1024².' },
    { tema:'UF4', p:'¿Qué función de PHP comprueba si un fichero existe?', ops:['is_file()','file_exists()','file_check()','exists_file()'], r:1, e:'file_exists() devuelve true tanto para ficheros como para directorios. is_file() verifica que sea específicamente un fichero.' },
    { tema:'UF4', p:'¿Qué método de BulkWrite permite insertar un elemento nuevo en una colección de MongoDB?', ops:['insert','insertMany','insertOne','add'], r:0, e:'El método insert de BulkWrite prepara una operación de inserción. insertOne y insertMany son métodos de la clase Collection, no de BulkWrite.' },
    { tema:'UF4', p:'¿Qué función PHP se usa para abrir un fichero para lectura/escritura?', ops:['file_open()','fread()','fopen()','open_file()'], r:2, e:'fopen($ruta, $modo) abre un fichero y devuelve un recurso. Los modos más comunes: "r" (leer), "w" (escribir), "a" (añadir), "r+" (leer y escribir).' },
    { tema:'UF4', p:'¿Qué función PHP lee todo el contenido de un fichero en un string de una sola vez?', ops:['fread()','file_read()','file_get_contents()','fgets()'], r:2, e:'file_get_contents() lee el contenido completo de un fichero en un string. También puede hacer peticiones HTTP.' },
    { tema:'UF4', p:'¿Qué función PHP lee el contenido de un fichero y devuelve cada línea como un elemento de array?', ops:['file_get_contents()','fgets()','file()','readlines()'], r:2, e:'file() lee el fichero completo y devuelve un array donde cada elemento es una línea del fichero, incluyendo el salto de línea.' },
    { tema:'UF4', p:'¿Qué ventaja principal ofrece PDO frente a las extensiones mysqli o mysql en PHP?', ops:['PDO es más rápido en consultas SELECT','PDO permite cambiar el SGBD (MySQL, PostgreSQL, SQLite...) cambiando solo la cadena de conexión','PDO incluye ORM integrado','PDO no requiere preparar sentencias'], r:1, e:'PDO (PHP Data Objects) es una abstracción que permite usar distintos SGBDs con la misma API. Solo se cambia el DSN de conexión.' },
    { tema:'UF4', p:'¿Por qué se usan sentencias preparadas con PDO?', ops:['Son más rápidas siempre','Previenen la inyección SQL al separar el código SQL de los datos','Permiten ejecutar múltiples sentencias en paralelo','Son la única forma de hacer transacciones'], r:1, e:'Las sentencias preparadas separan el código SQL de los parámetros. El SGBD analiza el SQL sin los datos, eliminando el riesgo de inyección SQL.' },
    { tema:'UF4', p:'¿Cómo se inicia una transacción con PDO?', ops:['$pdo->startTransaction()','$pdo->beginTransaction()','$pdo->transaction_begin()','$pdo->openTransaction()'], r:1, e:'$pdo->beginTransaction() inicia una transacción. Los cambios no se consolidan hasta commit() o se deshacen con rollback().' },
    { tema:'UF4', p:'¿Qué devuelve json_encode() aplicado a un array PHP?', ops:['Un objeto stdClass','Una cadena de texto en formato JSON','Un array de strings','Un archivo .json en disco'], r:1, e:'json_encode() convierte un array (u objeto) PHP en una cadena de texto JSON válida para intercambio de datos.' },
    { tema:'UF4', p:'¿Qué función PHP borra (elimina) un fichero del sistema de archivos?', ops:['delete()','file_delete()','unlink()','remove()'], r:2, e:'unlink($nombre) elimina el fichero del sistema de archivos. Devuelve true si tuvo éxito.' },
    { tema:'UF4', p:'¿Qué función PHP copia un fichero de una ruta a otra?', ops:['file_copy()','move()','copy()','cp()'], r:2, e:'copy($origen, $destino) copia el fichero. rename() puede usarse para mover o renombrar ficheros.' },
    { tema:'UF4', p:'En MongoDB, ¿cómo se llaman los equivalentes a las filas de una tabla relacional?', ops:['Registros','Tuplas','Documentos','Objetos'], r:2, e:'MongoDB almacena datos como documentos BSON (similar a JSON). Las colecciones agrupan documentos, equivalente a tablas en SQL.' },
    { tema:'UF4', p:'¿Qué función PHP obtiene el espacio libre en bytes de un sistema de archivos?', ops:['disk_space()','free_disk()','disk_free_space()','fs_free()'], r:2, e:'disk_free_space($ruta) devuelve el espacio libre en bytes. disk_total_space() devuelve el espacio total.' },
    { tema:'UF4', p:'¿Qué función PHP escribe una cadena de texto en un fichero ya abierto?', ops:['file_write()','write()','fwrite()','fputs_file()'], r:2, e:'fwrite($recurso, $cadena) escribe en el fichero apuntado por el recurso devuelto por fopen(). Es el complemento de fread().' },
    { tema:'UF4', p:'¿Qué modo de apertura de fopen() abre el fichero solo para lectura, colocando el puntero al inicio?', ops:['"a"','"w"','"r"','"x"'], r:2, e:'"r" abre para lectura. "w" abre para escritura (y trunca). "a" abre para añadir al final. "x" crea un nuevo fichero (falla si existe).' },
    { tema:'UF4', p:'¿Qué función PHP lee una línea completa de un fichero?', ops:['fread()','fgets()','file_line()','readline()'], r:1, e:'fgets($recurso) lee una línea del fichero, incluyendo el salto de línea. Es ideal para procesar ficheros línea a línea.' },
    { tema:'UF4', p:'¿Qué método PDO se usa para obtener el ID del último registro insertado?', ops:['$pdo->getLastId()','$pdo->lastInsertId()','$stmt->lastId()','$pdo->insertedId()'], r:1, e:'$pdo->lastInsertId() devuelve el valor del campo autoincremental del último INSERT ejecutado con éxito.' },
    { tema:'UF4', p:'¿Qué significa CRUD en el contexto de bases de datos?', ops:['Create, Read, Update, Delete','Copy, Replace, Undo, Distribute','Connect, Request, Unlock, Deploy','Create, Render, Upload, Download'], r:0, e:'CRUD = Create (INSERT), Read (SELECT), Update (UPDATE), Delete (DELETE). Son las cuatro operaciones básicas de persistencia de datos.' },
    { tema:'UF4', p:'¿Cómo se añade un modo de error a PDO para que lance excepciones automáticamente?', ops:['$pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION)','$pdo->setErrorMode("exception")','PDO::throwExceptions(true)','$pdo->errorMode = PDO::EXCEPTION'], r:0, e:'setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION) hace que PDO lance PDOException en cualquier error, en lugar de devolver false silenciosamente.' },
    { tema:'UF4', p:'¿Qué función PHP crea un directorio en el sistema de archivos?', ops:['create_dir()','make_dir()','mkdir()','newdir()'], r:2, e:'mkdir($ruta, $modo, $recursivo) crea el directorio. Con el tercer parámetro en true puede crear directorios anidados.' },
    { tema:'UF4', p:'¿Qué devuelve is_writable() en PHP?', ops:['true si el fichero existe','true si el fichero es un enlace simbólico','true si el fichero existe y tiene permisos de escritura','true si el fichero es ejecutable'], r:2, e:'is_writable() devuelve true si el path existe Y el proceso PHP tiene permiso de escritura sobre él.' },
    { tema:'UF4', p:'¿Qué función PHP ejecuta una consulta SQL preparada?', ops:['query()','execute()','$stmt->execute()','run_query()'], r:2, e:'Con PDO: $stmt = $pdo->prepare($sql); $stmt->execute([$param]); Las sentencias preparadas evitan inyección SQL separando el código de los datos.' },
    { tema:'UF4', p:'¿Qué método PDO devuelve todos los resultados de una consulta como array?', ops:['$stmt->getAll()','$stmt->fetchAll()','$stmt->results()','$pdo->selectAll()'], r:1, e:'$stmt->fetchAll(PDO::FETCH_ASSOC) devuelve todas las filas como array de arrays asociativos. fetchAll(PDO::FETCH_OBJ) devuelve objetos. fetch() obtiene solo una fila.' },
    { tema:'UF4', p:'¿Qué es el ORM y cuál es su ventaja principal?', ops:['Una capa que mapea tablas de BD a objetos PHP, abstrayendo el SQL y permitiendo operar con la BD usando objetos','Un tipo de gestor de base de datos orientado a objetos','Un patrón de diseño para conexiones de red','Un sistema de caché de consultas SQL'], r:0, e:'ORM (Object-Relational Mapping) permite interactuar con la BD usando objetos PHP en lugar de SQL directo. Laravel usa Eloquent ORM.' },
    { tema:'UF4', p:'¿Qué es una transacción de base de datos?', ops:['Una consulta SELECT muy compleja','Un conjunto de operaciones SQL que se ejecutan como unidad atómica: o todas tienen éxito o ninguna','Un procedimiento almacenado en la BD','Una copia de seguridad de la base de datos'], r:1, e:'Las transacciones garantizan ACID (Atomicidad, Consistencia, Aislamiento, Durabilidad). Si falla cualquier operación, se hace rollback y la BD vuelve al estado anterior.' },
    { tema:'UF4', p:'¿Qué función PHP/PDO inicia una transacción?', ops:['$pdo->startTransaction()','$pdo->beginTransaction()','$pdo->begin()','$pdo->transaction()'], r:1, e:'$pdo->beginTransaction() inicia la transacción. Si todo va bien: $pdo->commit(). Si hay error: $pdo->rollBack(). Siempre usar en bloques try-catch.' },
    { tema:'UF4', p:'¿Qué ventaja ofrece el uso de índices en una base de datos?', ops:['Reducen el tamaño del archivo de base de datos','Aceleran las consultas SELECT evitando escaneos completos de tabla','Garantizan la unicidad de todos los campos','Automatizan las copias de seguridad'], r:1, e:'Los índices permiten al motor de BD encontrar filas sin escanear toda la tabla. Un índice en la columna WHERE puede pasar una consulta de segundos a milisegundos.' },
    { tema:'UF4', p:'¿Qué es el patrón Repository en acceso a datos?', ops:['Una clase que encapsula toda la lógica de acceso a datos, separándola de la lógica de negocio','Un sistema de control de versiones para esquemas de BD','Una caché de consultas SQL frecuentes','Un tipo de migración de base de datos'], r:0, e:'El patrón Repository centraliza el acceso a BD en una clase dedicada. El resto de la aplicación no sabe si los datos vienen de MySQL, un API o caché. Facilita el testing.' },
    { tema:'UF4', p:'¿Qué son las migraciones de base de datos en frameworks como Laravel?', ops:['Scripts SQL manuales para actualizar la BD','Archivos PHP versionados que definen cambios incrementales en el esquema de la BD de forma reproducible','Copias de seguridad automáticas del esquema','Scripts para mover datos entre entornos'], r:1, e:'Las migraciones definen cambios en el esquema como código versionado. php artisan migrate aplica los cambios; migrate:rollback los revierte.' },
    { tema:'UF4', p:'¿Qué hace la cláusula SQL JOIN?', ops:['Combina filas de dos o más tablas basándose en una condición de relación entre ellas','Ordena los resultados de una consulta','Filtra filas duplicadas','Crea una nueva tabla combinando dos existentes'], r:0, e:'JOIN combina filas de tablas relacionadas. INNER JOIN devuelve solo los coincidentes. LEFT JOIN devuelve todos de la izquierda aunque no haya coincidencia a la derecha.' },
    { tema:'UF4', p:'¿Qué tipo de dato SQL se usa para almacenar texto de longitud variable sin límite fijo?', ops:['VARCHAR','CHAR','TEXT','BLOB'], r:2, e:'TEXT almacena cadenas de longitud variable sin límite estricto (hasta 65KB). VARCHAR requiere especificar longitud máxima. CHAR es de longitud fija. BLOB para datos binarios.' },
    { tema:'UF4', p:'¿Qué es SQL Injection y cómo se previene en PHP?', ops:['Un error de sintaxis SQL que PHP corrige automáticamente','Un ataque que inyecta SQL malicioso en inputs. Se previene con sentencias preparadas (PDO, MySQLi).','Un sistema de optimización de consultas SQL','Una técnica de indexación de bases de datos'], r:1, e:'SQL Injection inserta código SQL en inputs para manipular la BD. Prevención: usar SIEMPRE sentencias preparadas ($pdo->prepare(); $stmt->execute([$input])). Nunca concatenar inputs directamente en el SQL.' },
    { tema:'UF4', p:'¿Qué es una vista (VIEW) en SQL y qué ventaja tiene?', ops:['Una copia física de una tabla','Una consulta SQL almacenada como tabla virtual que simplifica consultas complejas y encapsula lógica de acceso a datos','Un índice especial para búsquedas rápidas','Un procedimiento almacenado de solo lectura'], r:1, e:'Una VIEW es una consulta SELECT guardada como objeto de la BD. Simplifica consultas complejas, añade una capa de seguridad y centraliza la lógica.' },
    { tema:'UF4', p:'¿Qué función PHP lee línea a línea un fichero CSV y la devuelve como array?', ops:['fread_csv()','file_get_csv()','fgetcsv()','csv_read()'], r:2, e:'fgetcsv($recurso, $longitud, $separador) lee una línea del CSV y la devuelve como array. Maneja las comillas escapadas automáticamente. fputcsv() hace la escritura.' },
  ],

  // ─────────────────────────────────────────────────────────
  // UF5 — LARAVEL I (MVC, rutas, controladores, Blade)
  // ─────────────────────────────────────────────────────────
  UF5: [
    { tema:'UF5', p:'¿Qué es un framework de desarrollo web?', ops:['Un editor de código especializado','Una plataforma o herramienta con funcionalidades predefinidas y patrones de diseño para crear aplicaciones de forma organizada','Un servidor web de alta disponibilidad','Un tipo de base de datos NoSQL'], r:1, e:'Un framework proporciona una estructura base con funcionalidades ya implementadas (seguridad, ORM, plantillas...) que ahorran tiempo y fuerzan buenas prácticas.' },
    { tema:'UF5', p:'¿Qué framework PHP tiene más demanda laboral según el temario UAX?', ops:['Symfony','CodeIgniter','Laravel','CakePHP'], r:2, e:'Laravel lidera la demanda laboral según búsquedas en InfoJobs citadas en el temario. Fue creado en 2011 y ha ganado enorme popularidad.' },
    { tema:'UF5', p:'En el patrón MVC, ¿qué capa gestiona el acceso a datos y la lógica de negocio?', ops:['Vista','Controlador','Modelo','Router'], r:2, e:'El Modelo contiene las clases con los datos y reglas de negocio. Los ORM facilitan el mapeo entre el modelo relacional y el modelo de objetos.' },
    { tema:'UF5', p:'En el patrón MVC, ¿qué capa es responsable de coordinar entre la Vista y el Modelo?', ops:['Router','Vista','Modelo','Controlador'], r:3, e:'El Controlador actúa de intermediario: recibe las peticiones HTTP, consulta el Modelo y envía los datos a la Vista para renderizarla.' },
    { tema:'UF5', p:'¿Qué herramienta se usa para instalar Laravel y gestionar sus dependencias?', ops:['npm','Artisan','Composer','Webpack'], r:2, e:'Composer es el gestor de dependencias de PHP. Se instala Laravel con: composer global require laravel/installer.' },
    { tema:'UF5', p:'¿Qué es Artisan en Laravel?', ops:['El motor de plantillas de Laravel','El ORM de Laravel','La interfaz de línea de comandos de Laravel para gestionar el proyecto','El gestor de dependencias de PHP'], r:2, e:'Artisan (php artisan) es la CLI de Laravel. Permite crear controladores, modelos, migraciones, ejecutar tareas, etc.' },
    { tema:'UF5', p:'¿En qué carpeta de Laravel se definen las rutas de la aplicación web?', ops:['app/routes','config','routes (archivo web.php)','resources/views'], r:2, e:'Las rutas web se definen en routes/web.php. Las rutas de API se definen en routes/api.php.' },
    { tema:'UF5', p:'¿Qué carpeta de Laravel es la única que debe ser públicamente accesible desde el servidor web?', ops:['app','storage','resources','public'], r:3, e:'La carpeta public contiene el index.php (punto de entrada) y los assets (CSS, JS, imágenes). El resto del proyecto no debe ser accesible desde el navegador.' },
    { tema:'UF5', p:'¿Qué archivo de Laravel contiene la configuración del entorno (credenciales de BD, modo debug, etc.)?', ops:['config/app.php','composer.json','.env','bootstrap/app.php'], r:2, e:'.env almacena configuración específica del entorno (desarrollo, producción). No debe versionarse (añadir al .gitignore).' },
    { tema:'UF5', p:'¿Qué carpeta de Laravel contiene las vistas (plantillas HTML)?', ops:['app/views','public/views','resources/views','storage/views'], r:2, e:'Las vistas (plantillas Blade .blade.php) se almacenan en resources/views. Los assets (CSS/JS) van en la carpeta public.' },
    { tema:'UF5', p:'¿Cuál es el motor de plantillas nativo de Laravel?', ops:['Twig','Smarty','Blade','Mustache'], r:2, e:'Blade es el motor de plantillas de Laravel. Permite usar estructuras de control (@if, @foreach...) y herencia de plantillas con @extends y @section.' },
    { tema:'UF5', p:'¿Qué sintaxis usa Blade para mostrar el valor de una variable escapando HTML?', ops:['&lt;?= $variable ?&gt;','{{ $variable }}','{!! $variable !!}','@echo($variable)'], r:1, e:'{{ $variable }} muestra el valor escapado (seguro contra XSS). {!! $variable !!} muestra el valor sin escapar (solo para HTML de confianza).' },
    { tema:'UF5', p:'¿Qué directiva Blade se usa para iterar sobre una colección?', ops:['@for','@each','@foreach','@loop'], r:2, e:'@foreach ($items as $item) ... @endforeach itera sobre colecciones. Laravel añade la variable $loop con información del bucle.' },
    { tema:'UF5', p:'¿Qué comando Artisan crea un nuevo controlador en Laravel?', ops:['php artisan new:controller','php artisan create controller','php artisan make:controller NombreController','php artisan generate:controller'], r:2, e:'php artisan make:controller NombreController crea el archivo del controlador en app/Http/Controllers.' },
    { tema:'UF5', p:'¿Cómo se valida un formulario en Laravel desde el propio controlador?', ops:['Con la función validate() de la petición $request','Con la clase Validator::check()','Con preg_match() en el controlador','Con htmlspecialchars() en la vista'], r:0, e:'$request->validate([\'campo\' => \'required|max:255\']) valida automáticamente. Si falla, redirige al formulario con los errores en $errors.' },
    { tema:'UF5', p:'¿Cuál es una DESVENTAJA del uso de frameworks frente a PHP nativo?', ops:['Peor seguridad','Mayor carga de proceso y rendimiento inferior al incluir código no siempre necesario','No permiten trabajo en equipo','No tienen sistema de caché'], r:1, e:'Los frameworks cargan muchas clases y abstracciones aunque no se usen, lo que puede afectar al rendimiento frente a código PHP nativo optimizado.' },
    { tema:'UF5', p:'¿Qué directiva Blade se usa para incluir una subvista dentro de otra vista?', ops:['@use','@component','@include','@import'], r:2, e:'@include(\'ruta.vista\') incluye una vista parcial dentro de otra. Es útil para reutilizar cabeceras, pies de página, etc.' },
    { tema:'UF5', p:'¿Cómo se pasan variables a una vista desde un controlador en Laravel?', ops:['Directamente con view(\'nombre\')','Con return view(\'nombre\', [\'clave\' => $valor]) o compact()','Usando variables globales','Con $_GET o $_POST'], r:1, e:'view(\'nombre\', [\'clave\' => $valor]) o view(\'nombre\')->with(\'clave\', $valor) pasan datos a la vista. compact() es un atajo.' },
    { tema:'UF5', p:'¿Qué framework PHP fue creado en 2011 y utiliza el core de Symfony en un 30%?', ops:['CodeIgniter','CakePHP','Phalcon','Laravel'], r:3, e:'Laravel fue creado en 2011 por Taylor Otwell. Usa el 30% del código de Symfony (componentes HttpFoundation, Routing, Console...) como base.' },
    { tema:'UF5', p:'¿Qué framework PHP destaca por estar escrito en C y compilarse como extensión de Apache o Nginx?', ops:['Symfony','CodeIgniter','Phalcon','Laravel'], r:2, e:'Phalcon (2012) está escrito en C y se instala como extensión nativa. Su principal ventaja es el rendimiento superior frente a frameworks PHP puros.' },
    { tema:'UF5', p:'¿Qué carpeta de Laravel almacena las librerías instaladas por Composer?', ops:['lib','packages','node_modules','vendor'], r:3, e:'La carpeta vendor contiene todas las dependencias del framework y paquetes de terceros instalados con Composer. No debe modificarse.' },
    { tema:'UF5', p:'¿Qué directiva Blade permite la herencia de plantillas, indicando qué layout extiende la vista actual?', ops:['@layout','@parent','@extends','@template'], r:2, e:'@extends("layouts.app") indica que la vista hereda del layout especificado. Las secciones se definen con @section y se renderizan con @yield.' },
    { tema:'UF5', p:'¿Cuál es el parámetro de configuración del .env de Laravel que indica el tipo de motor de BD?', ops:['DB_TYPE','DB_ENGINE','DB_CONNECTION','DB_DRIVER'], r:2, e:'DB_CONNECTION indica el driver (mysql, pgsql, sqlite, sqlsrv...). El valor por defecto en config/database.php es mysql.' },
    { tema:'UF5', p:'¿Qué comando Artisan crea una nueva aplicación Laravel?', ops:['php artisan new proyecto','composer create-project laravel/laravel nombre','laravel new nombre','npm init laravel'], r:2, e:'laravel new nombre (con el instalador de Laravel) o composer create-project laravel/laravel nombre crean un nuevo proyecto.' },
    { tema:'UF5', p:'¿Qué carpeta de Laravel contiene el código principal de la aplicación (controladores, modelos, middleware)?', ops:['src','core','app','lib'], r:2, e:'La carpeta app/ es el corazón del proyecto: contiene Http (controladores, middleware), Models, Providers, etc.' },
    { tema:'UF5', p:'¿Cómo se genera una ruta con nombre (named route) en Laravel?', ops:['Route::get("/ruta", ...)->alias("nombre")','Route::get("/ruta", ...)->name("nombre")','Route::named("/ruta", "nombre", ...)','Route::as("nombre", "/ruta", ...)'], r:1, e:'->name("nombre") asigna un alias a la ruta. Luego se puede usar route("nombre") en vistas y controladores para generar la URL.' },
    { tema:'UF5', p:'¿Qué es el patrón MVC?', ops:['Model-View-Controller: separa datos, presentación y lógica de control para organizar el código de forma mantenible','Model-View-Component: arquitectura de Vue.js','Multiple-View-Controller: para múltiples interfaces','Maximum-Viable-Concept: metodología ágil'], r:0, e:'MVC separa: Model (datos y lógica de negocio), View (presentación/HTML), Controller (recibe peticiones, coordina modelo y vista). Mejora la organización, el testing y el mantenimiento del código.' },
    { tema:'UF5', p:'¿Qué es el enrutamiento (routing) en un framework MVC?', ops:['La gestión de las conexiones de red del servidor','El mecanismo que mapea URLs de peticiones HTTP a controladores y acciones específicas','El sistema de caché de vistas','El procesamiento de formularios POST'], r:1, e:'El router analiza la URL y método HTTP (GET, POST...) de cada petición y la dirige al controlador y método (acción) correspondiente.' },
    { tema:'UF5', p:'¿Qué hace un middleware en un framework web?', ops:['Gestiona las conexiones a la base de datos','Código que se ejecuta entre la petición HTTP y el controlador, para autenticación, logging, CORS, etc.','Un sistema de plantillas HTML','La capa de acceso a datos'], r:1, e:'Los middlewares interceptan la petición antes de llegar al controlador. Usos: verificar autenticación, registrar acceso, añadir cabeceras CORS, limitar rate, sanitizar inputs.' },
    { tema:'UF5', p:'¿Qué es Composer en el ecosistema PHP?', ops:['Un editor de texto para PHP','El gestor de dependencias de PHP que descarga e instala librerías y gestiona el autoload','Un servidor web para PHP','Una herramienta de testing PHP'], r:1, e:'Composer gestiona las librerías PHP del proyecto. composer.json define las dependencias; composer install las descarga en vendor/. Genera el autoloader PSR-4.' },
    { tema:'UF5', p:'¿Qué es PSR en PHP?', ops:['PHP Standard Request — formato de peticiones HTTP','PHP-FIG Standard Recommendations — estándares de codificación y interoperabilidad para el ecosistema PHP','PHP Security Requirements — requisitos de seguridad de PHP','Protocolo de sincronización de repositorios PHP'], r:1, e:'PSR (PHP Standard Recommendations) son estándares del PHP-FIG. Los más importantes: PSR-1/PSR-2/PSR-12 (estilo de código), PSR-4 (autoloading), PSR-7 (mensajes HTTP).' },
    { tema:'UF5', p:'¿Qué es CSRF y cómo lo maneja Laravel?', ops:['Un tipo de inyección SQL','Cross-Site Request Forgery — Laravel incluye automáticamente tokens CSRF en formularios con @csrf para prevenirlo','Un sistema de caché de formularios','Un protocolo de comunicación segura entre cliente y servidor'], r:1, e:'Laravel genera un token CSRF único por sesión. @csrf en los formularios Blade añade el campo _token. El middleware VerifyCsrfToken verifica que el token enviado coincide con el de la sesión.' },
    { tema:'UF5', p:'¿Qué es la inyección de dependencias en Laravel (Service Container)?', ops:['Una vulnerabilidad de seguridad que Laravel previene','El contenedor IoC de Laravel que resuelve automáticamente las dependencias de los controladores y servicios','El sistema de gestión de sesiones de Laravel','El sistema de caché de Laravel'], r:1, e:'El Service Container de Laravel resuelve automáticamente las dependencias declaradas en los constructores. Type-hinting una clase en el controlador: Laravel la instancia y la inyecta automáticamente.' },
    { tema:'UF5', p:'¿Qué son los seeders en Laravel?', ops:['Comandos para deshacer migraciones','Scripts que rellenan la BD con datos de prueba de forma reproducible','Archivos de configuración de la BD','Herramientas de exportación de datos'], r:1, e:'Los seeders rellenan la BD con datos de prueba (php artisan db:seed). Se combinan con las factories para generar datos aleatorios realistas.' },
    { tema:'UF5', p:'¿Qué es el scaffolding en Laravel?', ops:['Un sistema de plantillas HTML','La generación automática de código repetitivo (CRUD completo) con comandos Artisan para acelerar el desarrollo inicial','Un sistema de testing automático','Una herramienta de despliegue'], r:1, e:'El scaffolding genera código base: php artisan make:model Producto -mcr crea el modelo, la migración y el controlador resource con todos los métodos CRUD en un solo comando.' },
    { tema:'UF5', p:'¿Qué son los Form Requests en Laravel?', ops:['Objetos que encapsulan la validación y autorización de formularios en una clase dedicada, separando esa lógica del controlador','Arrays especiales para datos POST','Middlewares de autenticación','Plantillas Blade para formularios'], r:0, e:'Los Form Requests (php artisan make:request StoreProductoRequest) contienen las reglas de validación en rules() y la autorización en authorize(). El controlador solo recibe datos ya válidos.' },
  ],

  // ─────────────────────────────────────────────────────────
  // UF6 — LARAVEL II / ORM ELOQUENT
  // ─────────────────────────────────────────────────────────
  UF6: [
    { tema:'UF6', p:'¿Qué es un ORM?', ops:['Un sistema de gestión de bases de datos','Un modelo de programación que mapea estructuras de BD relacional sobre entidades de objetos','Un tipo de servidor de aplicaciones','Un protocolo de comunicación entre BD'], r:1, e:'ORM (Object-Relational Mapping) mapea tablas de BD relacional a clases PHP, permitiendo operar con datos como objetos sin escribir SQL.' },
    { tema:'UF6', p:'¿Cómo se llama el ORM nativo de Laravel?', ops:['Doctrine','Hibernate','Eloquent','Propel'], r:2, e:'Eloquent es el ORM activo de Laravel. Permite realizar operaciones CRUD complejas sin escribir SQL, usando métodos encadenados.' },
    { tema:'UF6', p:'¿Qué son las migraciones en Laravel?', ops:['Archivos de configuración del servidor','Una especie de control de versiones para la base de datos que permite crear y modificar el esquema fácilmente','Scripts de copia de seguridad','Archivos de traducción de la aplicación'], r:1, e:'Las migraciones son clases PHP en database/migrations que definen la estructura de la BD. Permiten reproducir el esquema en cualquier entorno.' },
    { tema:'UF6', p:'¿Qué comando Artisan ejecuta las migraciones pendientes?', ops:['php artisan db:migrate','php artisan migration:run','php artisan migrate','php artisan schema:update'], r:2, e:'php artisan migrate ejecuta el método up() de todas las migraciones pendientes. php artisan migrate:rollback deshace el último lote.' },
    { tema:'UF6', p:'¿Qué dos métodos debe tener obligatoriamente una migración Laravel?', ops:['create() y drop()','run() y revert()','up() y down()','execute() y rollback()'], r:2, e:'up() aplica los cambios (crear/modificar tabla). down() los revierte. Esto permite hacer rollback de migraciones.' },
    { tema:'UF6', p:'¿Dónde se configuran las credenciales de conexión a la base de datos en Laravel?', ops:['En config/app.php','En el archivo .env','En app/Http/Controllers/DBController.php','En routes/web.php'], r:1, e:'Las credenciales (DB_HOST, DB_DATABASE, DB_USERNAME, DB_PASSWORD) se definen en el archivo .env, que no debe versionarse.' },
    { tema:'UF6', p:'¿Qué comando Artisan crea un modelo Eloquent en Laravel?', ops:['php artisan new:model','php artisan make:model Nombre','php artisan create:model','php artisan generate Nombre'], r:1, e:'php artisan make:model Nombre crea el modelo en app/Models/. Con -m también genera la migración asociada.' },
    { tema:'UF6', p:'¿Qué método Eloquent devuelve todos los registros de una tabla?', ops:['Model::find()','Model::get()','Model::all()','Model::fetch()'], r:2, e:'Model::all() devuelve una Colección con todos los registros. Model::find($id) devuelve un único registro por clave primaria.' },
    { tema:'UF6', p:'¿Cómo se guarda un nuevo registro en la base de datos usando Eloquent?', ops:['Model::insert($datos)','$objeto->save() tras asignar atributos','Model::create_new($datos)','$db->insert($objeto)'], r:1, e:'Se crea una instancia del modelo, se asignan atributos y se llama a $objeto->save(). También puede usarse Model::create([...]).' },
    { tema:'UF6', p:'¿Qué es la inyección de dependencias en el contexto de Laravel?', ops:['Inyectar código SQL directamente en las consultas','Un mecanismo que pasa las dependencias de un objeto a través de su constructor o métodos, en lugar de crearlas dentro del propio objeto','Cargar automáticamente todos los archivos PHP del proyecto','Configurar las variables de entorno'], r:1, e:'DI pasa las dependencias (otros objetos que necesita una clase) desde fuera. Laravel lo gestiona con el Service Container, que resuelve dependencias automáticamente.' },
    { tema:'UF6', p:'¿Qué objeto se pasa automáticamente a los métodos del controlador para acceder a los datos de la petición HTTP?', ops:['$http','$req','$request (instancia de Request)','$input'], r:2, e:'Laravel inyecta automáticamente un objeto Request al declararlo como tipo en la firma del método. Permite acceder a parámetros, archivos, sesión, etc.' },
    { tema:'UF6', p:'¿Qué método Eloquent devuelve el primer registro que coincide con una condición?', ops:['Model::find()','Model::where()->first()','Model::get()->first','Model::search()'], r:1, e:'Model::where(\'campo\', $valor)->first() aplica la condición y devuelve el primer resultado. find() busca por clave primaria.' },
    { tema:'UF6', p:'¿Cómo se define una relación "uno a muchos" en Eloquent?', ops:['Usando el método belongsTo() en ambos modelos','Usando hasMany() en el modelo padre y belongsTo() en el hijo','Usando hasOne() en ambos modelos','Usando manyToOne() en el modelo hijo'], r:1, e:'El modelo padre usa hasMany(\'Hijo::class\') y el hijo usa belongsTo(\'Padre::class\'). Eloquent gestiona automáticamente las claves foráneas.' },
    { tema:'UF6', p:'¿Qué modificador de migración Eloquent indica que un campo puede ser NULL?', ops:['->optional()','->allowNull()','->nullable()','->null(true)'], r:2, e:'->nullable() permite que el campo acepte valores NULL en la base de datos. Sin él, el campo es NOT NULL por defecto.' },
    { tema:'UF6', p:'¿Qué hace php artisan migrate:rollback?', ops:['Elimina toda la base de datos','Deshace el último lote de migraciones ejecutadas','Recrea todas las migraciones desde cero','Muestra el historial de migraciones'], r:1, e:'rollback() deshace el último lote (batch) de migraciones, ejecutando el método down() de cada migración de ese lote.' },
    { tema:'UF6', p:'¿Qué método Eloquent se usa para eliminar un registro de la base de datos?', ops:['$objeto->remove()','$objeto->destroy()','$objeto->delete()','Model::drop($id)'], r:2, e:'$objeto->delete() elimina el registro correspondiente. También existe Model::destroy($id) como atajo.' },
    { tema:'UF6', p:'¿Qué ORM usa Laravel para gestionar el acceso a bases de datos?', ops:['Doctrine','Hibernate','Sequelize','Eloquent'], r:3, e:'Eloquent es el ORM activo incluido en Laravel. Permite operar con la BD como si fueran objetos PHP, sin escribir SQL manualmente.' },
    { tema:'UF6', p:'¿Qué método Eloquent se usa para buscar un registro por su clave primaria y lanzar excepción si no existe?', ops:['Model::find()','Model::findOrNew()','Model::findOrFail()','Model::get($id)'], r:2, e:'findOrFail($id) lanza una ModelNotFoundException si el registro no existe, lo que en Laravel devuelve automáticamente un 404.' },
    { tema:'UF6', p:'¿Qué tipo de dato usa Eloquent por defecto para los campos created_at y updated_at?', ops:['integer (timestamp Unix)','string (fecha formateada)','timestamp (gestionado automáticamente por Eloquent)','date'], r:2, e:'timestamps() en la migración crea created_at y updated_at como TIMESTAMP. Eloquent los actualiza automáticamente en create y update.' },
    { tema:'UF6', p:'¿Cómo se define en Eloquent que un modelo pertenece a otro (relación N:1)?', ops:['$this->hasOne()','$this->hasMany()','$this->belongsTo()','$this->morphTo()'], r:2, e:'belongsTo() en el modelo hijo define la relación inversa: "Este modelo pertenece a Padre". Eloquent buscará la clave foránea automáticamente.' },
    { tema:'UF6', p:'¿Qué método ORM de Eloquent permite filtrar resultados con una condición WHERE?', ops:['filter()','search()','where()','condition()'], r:2, e:'Model::where("campo", "valor") añade una cláusula WHERE. Se pueden encadenar múltiples where() antes de llamar get() o first().' },
    { tema:'UF6', p:'¿Qué comando Artisan crea una migración Y el modelo al mismo tiempo en Laravel?', ops:['php artisan make:migration Modelo -m','php artisan make:model Modelo -m','php artisan make:all Modelo','php artisan create Modelo --migration'], r:1, e:'php artisan make:model Modelo -m crea el modelo en app/Models Y genera la migración correspondiente en database/migrations.' },
    { tema:'UF6', p:'¿Qué pasa cuando se ejecuta php artisan migrate:fresh?', ops:['Solo ejecuta las migraciones pendientes','Hace rollback del último lote','Elimina TODAS las tablas y vuelve a ejecutar todas las migraciones desde cero','Muestra el estado de las migraciones'], r:2, e:'migrate:fresh borra todas las tablas (DROP TABLE) y re-ejecuta todas las migraciones. Útil en desarrollo para reiniciar la BD.' },
    { tema:'UF6', p:'¿Qué es una API REST?', ops:['Una librería PHP para consumir APIs','Una arquitectura para servicios web que usa HTTP, recursos identificados por URLs, verbos HTTP y representaciones JSON/XML','Un protocolo de comunicación segura','Un sistema de gestión de versiones de APIs'], r:1, e:'REST (Representational State Transfer) define un conjunto de principios: recursos identificados por URLs, operaciones con verbos HTTP (GET, POST, PUT, DELETE), respuestas sin estado y representaciones (JSON, XML).' },
    { tema:'UF6', p:'¿Qué verbo HTTP se usa para actualizar parcialmente un recurso en REST?', ops:['PUT','POST','PATCH','DELETE'], r:2, e:'PATCH actualiza parcialmente (solo los campos enviados). PUT reemplaza el recurso completo. POST crea. GET lee. DELETE elimina.' },
    { tema:'UF6', p:'¿Qué código de estado HTTP indica que el recurso fue creado correctamente?', ops:['200 OK','201 Created','204 No Content','302 Found'], r:1, e:'201 Created se devuelve al crear un recurso con POST. 200 OK para respuestas exitosas generales. 204 No Content para DELETE exitoso sin cuerpo.' },
    { tema:'UF6', p:'¿Qué es JWT (JSON Web Token)?', ops:['Un formato de base de datos JSON','Un estándar para tokens de autenticación compactos y autoverificables: header.payload.signature','Un protocolo HTTP de autenticación basado en cookies','Un sistema de cifrado de bases de datos JSON'], r:1, e:'JWT consta de tres partes codificadas en Base64 separadas por puntos: header (algoritmo), payload (datos/claims) y signature (verificación).' },
    { tema:'UF6', p:'¿Qué es CORS y por qué es importante en APIs?', ops:['Un protocolo de cifrado de APIs','Cross-Origin Resource Sharing: política del navegador que controla qué orígenes pueden hacer peticiones a una API de otro dominio','Un formato de respuesta alternativo a JSON','Un sistema de autenticación OAuth'], r:1, e:'CORS es una política de seguridad del navegador. Por defecto bloquea peticiones a dominios diferentes. Las APIs deben añadir cabeceras (Access-Control-Allow-Origin) para permitir orígenes específicos.' },
    { tema:'UF6', p:'¿Qué es la autenticación Bearer Token?', ops:['Autenticación con usuario y contraseña en cada petición','El cliente envía un token en la cabecera Authorization: Bearer {token} para autenticar cada petición a la API','Un sistema de autenticación mediante certificados SSL','Autenticación mediante cookies HTTP'], r:1, e:'Bearer Token: el cliente incluye Authorization: Bearer eyJ... en cada petición HTTP. El servidor valida el token (JWT o token opaco en BD). Es stateless.' },
    { tema:'UF6', p:'¿Qué son los recursos en una API RESTful?', ops:['Los archivos estáticos servidos por la API','Las entidades del dominio (usuarios, productos, pedidos) accesibles mediante URLs y operaciones HTTP','Los servidores donde se aloja la API','Las librerías PHP usadas por la API'], r:1, e:'En REST, todo es un recurso: /usuarios, /productos/42, /pedidos/7/items. Cada recurso tiene una URL única. Los verbos HTTP definen la operación sobre el recurso.' },
    { tema:'UF6', p:'¿Qué es la documentación OpenAPI/Swagger?', ops:['Una librería PHP para generar APIs automáticamente','Un estándar para describir APIs REST de forma legible por máquinas y humanos, generando documentación interactiva','Un framework PHP alternativo a Laravel','Un sistema de testing de APIs'], r:1, e:'OpenAPI (antes Swagger) es el estándar para documentar APIs REST. Define endpoints, parámetros, respuestas y autenticación en YAML/JSON. Swagger UI genera una interfaz interactiva.' },
    { tema:'UF6', p:'¿Qué es la paginación en APIs REST y por qué es necesaria?', ops:['La división de la API en versiones (v1, v2)','Dividir grandes conjuntos de resultados en páginas para evitar sobrecarga del servidor y cliente','La compresión de respuestas JSON grandes','El sistema de caché de respuestas de la API'], r:1, e:'Sin paginación, un GET /productos podría devolver millones de registros. La paginación limita los resultados: GET /productos?page=2&limit=20.' },
    { tema:'UF6', p:'¿Qué diferencia hay entre autenticación y autorización?', ops:['Son sinónimos en el contexto de APIs','Autenticación: verificar identidad (¿quién eres?). Autorización: verificar permisos (¿qué puedes hacer?).','Autorización: verificar identidad. Autenticación: verificar permisos.','Autenticación es para APIs públicas; autorización para APIs privadas'], r:1, e:'Autenticación (AuthN): ¿eres quien dices ser? (login). Autorización (AuthZ): ¿tienes permiso para hacer esto? (roles, scopes). Puedes estar autenticado pero no autorizado para un recurso.' },
    { tema:'UF6', p:'¿Qué es el rate limiting en APIs?', ops:['La limitación de tamaño máximo de respuestas JSON','La restricción del número de peticiones que un cliente puede hacer en un período de tiempo','La limitación de versiones simultáneas de la API','La compresión automática de respuestas grandes'], r:1, e:'El rate limiting previene el abuso de la API (sobrecarga, scraping, ataques). Ejemplo: máximo 100 peticiones/minuto por IP. Laravel: middleware throttle.' },
    { tema:'UF6', p:'¿Qué ventaja tiene usar JSON sobre XML en APIs REST modernas?', ops:['JSON es más seguro que XML','JSON es más ligero, fácil de parsear en JavaScript y más legible, por eso ha desplazado a XML en APIs modernas','XML permite tipos de datos más complejos','JSON soporta más caracteres especiales'], r:1, e:'JSON pesa menos que XML, es nativo en JavaScript (JSON.parse/stringify), más legible y tiene mejor soporte en todas las plataformas.' },
    { tema:'UF6', p:'¿Qué es GraphQL y en qué se diferencia de REST?', ops:['Un dialecto SQL para bases de datos de grafos','Un lenguaje de consulta para APIs donde el cliente especifica exactamente qué datos necesita, evitando over/underfetching','Un framework PHP alternativo a Laravel','Un protocolo de comunicación en tiempo real'], r:1, e:'REST tiene endpoints fijos. GraphQL tiene un único endpoint; el cliente especifica exactamente qué campos necesita. Evita overfetching y underfetching.' },
    { tema:'UF6', p:'¿Qué es el eager loading en Eloquent y por qué es importante?', ops:['Cargar todos los modelos al iniciar la app','Cargar las relaciones junto con el modelo principal en una sola consulta para evitar el problema N+1','Un sistema de caché de modelos','La precarga de vistas Blade'], r:1, e:'Sin eager loading: 1 query para usuarios + N queries para posts de cada uno = N+1 queries. Con User::with(\'posts\')->get() = solo 2 queries. Crítico para el rendimiento.' },
  ],

  // ─────────────────────────────────────────────────────────
  // UF7 — SERVICIOS WEB REST
  // ─────────────────────────────────────────────────────────
  UF7: [
    { tema:'UF7', p:'¿Qué es un servicio web (web service)?', ops:['Una página web con diseño responsive','Una interfaz mediante la que dos máquinas o aplicaciones se comunican entre sí a través de Internet','Un servidor dedicado a servir contenido estático','Un protocolo de transferencia de archivos'], r:1, e:'Un web service facilita un servicio a través de Internet: es una interfaz multiplataforma y distribuida que permite la comunicación entre aplicaciones.' },
    { tema:'UF7', p:'¿Cuál es la característica principal que distingue a los servicios web de otros protocolos como FTP o SMTP?', ops:['Son más rápidos que otros protocolos','Usan HTTP como transporte, lo que les permite pasar cortafuegos y funcionar en cualquier servidor web','Solo pueden transmitir XML','Requieren autenticación OAuth siempre'], r:1, e:'Los web services usan HTTP (puerto 80/443), por lo que cualquier equipo que pueda acceder a una web puede usarlos. Pasan cortafuegos sin problemas.' },
    { tema:'UF7', p:'¿Qué porcentaje aproximado de los servicios web distribuye REST actualmente según el temario?', ops:['30%','50%','70%','90%'], r:2, e:'REST distribuye aproximadamente el 70% de los servicios web en la actualidad, habiendo superado ampliamente a SOAP.' },
    { tema:'UF7', p:'¿Qué protocolo usa SOAP para transportar sus mensajes en la mayoría de los casos?', ops:['FTP','SMTP','HTTP','TCP directo'], r:2, e:'SOAP suele usar HTTP aunque no está limitado a él. También puede usar FTP, POP3 o colas de mensajería (JMS, MQ).' },
    { tema:'UF7', p:'¿En qué formato de datos se basa la comunicación SOAP?', ops:['JSON','XML exclusivamente','YAML','CSV'], r:1, e:'SOAP solo admite XML. Sus mensajes deben ser parseados a árbol DOM antes de procesarse, lo que lo hace más pesado que REST.' },
    { tema:'UF7', p:'¿Cuál es una ventaja de SOAP sobre REST en materia de seguridad?', ops:['SOAP no necesita autenticación','SOAP incorpora WS-Security, un estándar de seguridad anclado en el propio protocolo','REST no soporta HTTPS','SOAP cifra automáticamente todos los mensajes'], r:1, e:'WS-Security es una especificación de seguridad integrada en SOAP. REST depende de seguridad a nivel de transporte (HTTPS, JWT, OAuth).' },
    { tema:'UF7', p:'¿Qué métodos HTTP utiliza REST para las operaciones CRUD?', ops:['Solo GET y POST','GET, POST, PUT, DELETE (y opcionalmente PATCH)','Solo GET','GET, POST y HEAD'], r:1, e:'REST mapea: GET (leer), POST (crear), PUT (actualizar completo), PATCH (actualizar parcial), DELETE (borrar). Son los métodos HTTP estándar.' },
    { tema:'UF7', p:'¿Qué formato de datos usa REST principalmente, aunque admite otros?', ops:['XML','YAML','JSON','HTML'], r:2, e:'REST admite XML, JSON, binarios, texto, etc. Pero JSON domina por su integración nativa con JavaScript y frameworks como Angular y React.' },
    { tema:'UF7', p:'¿Qué herramienta se usa para probar servicios REST sin un frontend?', ops:['phpMyAdmin','curl desde terminal','Postman','Laravel Artisan'], r:2, e:'Postman es la herramienta más popular para probar APIs REST. Permite configurar peticiones HTTP, headers, body y ver las respuestas.' },
    { tema:'UF7', p:'¿Qué es Express en el contexto de Node.js?', ops:['Un motor de plantillas','Un framework web minimalista para Node.js que simplifica la creación de servidores y APIs','Un gestor de paquetes alternativo a npm','Un ORM para bases de datos NoSQL'], r:1, e:'Express.js es el framework web más popular de Node.js. Proporciona routing, middleware y gestión de peticiones/respuestas de forma sencilla.' },
    { tema:'UF7', p:'¿Qué ventaja ofrece la autenticación basada en tokens JWT frente a las sesiones de servidor?', ops:['Los tokens JWT son más seguros que cualquier otra alternativa','No requieren almacenamiento de estado en el servidor (stateless), lo que facilita el escalado','JWT siempre expira a los 5 minutos','Los tokens JWT no caducan nunca'], r:1, e:'JWT es stateless: toda la información va en el propio token. El servidor no necesita almacenar sesiones, lo que facilita el escalado horizontal.' },
    { tema:'UF7', p:'¿Qué son las siglas SOAP?', ops:['Simple Object Access Protocol','Secure Object API Protocol','Server-Oriented API Protocol','Simple Open Architecture Protocol'], r:0, e:'SOAP = Simple Object Access Protocol. Es un protocolo estándar para intercambio de información estructurada (XML) entre sistemas.' },
    { tema:'UF7', p:'¿Qué significa que un web service es "multiplataforma"?', ops:['Puede instalarse en Windows y Linux','Cliente y servidor no necesitan la misma configuración para comunicarse; el servicio web lo hace posible','Solo funciona con navegadores modernos','Requiere la misma versión de PHP en cliente y servidor'], r:1, e:'La multiplataformidad es característica clave de los web services: independizan a cliente y servidor de sus tecnologías específicas.' },
    { tema:'UF7', p:'¿Qué significa REST?', ops:['Remote Execution Scripting Technology','Representational State Transfer','Reliable Exchange of Structured Text','Rapid Endpoint Service Transfer'], r:1, e:'REST = Representational State Transfer. Es una arquitectura (no protocolo) que usa HTTP con sus métodos y códigos de estado nativos.' },
    { tema:'UF7', p:'En una API REST con Laravel, ¿qué comando Artisan crea un controlador específico para API?', ops:['php artisan make:controller ApiController --api','php artisan make:controller ApiController --resource','php artisan api:create NombreController','php artisan make:api NombreController'], r:0, e:'php artisan make:controller --api genera un controlador con los métodos index, store, show, update y destroy (sin create ni edit, que son vistas).' },
    { tema:'UF7', p:'¿Qué código de estado HTTP indica que un recurso se creó correctamente?', ops:['200 OK','201 Created','204 No Content','301 Moved Permanently'], r:1, e:'201 Created se devuelve tras un POST exitoso que crea un nuevo recurso. 200 OK es para GET exitosos.' },
    { tema:'UF7', p:'¿Qué código de estado HTTP indica que el cliente no tiene permisos para acceder a un recurso?', ops:['400 Bad Request','401 Unauthorized','403 Forbidden','404 Not Found'], r:2, e:'403 Forbidden significa que el servidor entiende la petición pero se niega a procesarla (sin permiso). 401 indica que falta autenticación.' },
    { tema:'UF7', p:'¿Qué estructura tienen las tres partes de un JWT?', ops:['Header.Claims.Timestamp','Algoritmo.Payload.Firma','Header.Payload.Signature (separados por puntos)','Token.Expiry.Hash'], r:2, e:'Un JWT tiene tres partes en Base64Url separadas por puntos: Header (algoritmo), Payload (datos/claims) y Signature (firma digital).' },
    { tema:'UF7', p:'En una API REST, ¿qué método HTTP se usa para actualizar completamente un recurso existente?', ops:['POST','GET','PUT','PATCH'], r:2, e:'PUT reemplaza el recurso completo. PATCH actualiza solo los campos enviados (actualización parcial).' },
    { tema:'UF7', p:'¿Qué significa que una API REST es "stateless"?', ops:['Que no guarda logs','Que cada petición debe contener toda la información necesaria para procesarla; el servidor no guarda estado entre peticiones','Que no usa bases de datos','Que las respuestas son siempre las mismas'], r:1, e:'Stateless: el servidor no guarda información de sesión entre peticiones. Cada petición es independiente y self-contained. Esto facilita el escalado.' },
    { tema:'UF7', p:'¿Qué estructura XML tiene el envelope de SOAP?', ops:['Header y Body','Envelope, Header y Body','Envelope y Body solamente','Request, Header y Response'], r:2, e:'Un mensaje SOAP tiene: SOAP-ENV:Envelope > SOAP-ENV:Header (opcional, con metadatos) > SOAP-ENV:Body (datos del mensaje).' },
    { tema:'UF7', p:'¿Qué es WSDL en el contexto de SOAP?', ops:['Web Standard Deployment Language','Web Service Description Language: describe los endpoints y operaciones de un servicio SOAP','Web Socket Data Layer','Wireless Service Definition Library'], r:1, e:'WSDL es un lenguaje XML que describe un servicio SOAP: qué operaciones ofrece, qué parámetros acepta y qué respuesta devuelve.' },
    { tema:'UF7', p:'¿Qué es Eloquent en Laravel?', ops:['El motor de plantillas de Laravel','El ORM de Laravel que permite interactuar con la BD usando modelos PHP en lugar de SQL directo','El sistema de rutas de Laravel','El contenedor de servicios de Laravel'], r:1, e:'Eloquent es el ORM ActiveRecord de Laravel. Cada tabla de BD tiene un Model PHP. User::find(1) hace SELECT; $user->save() hace INSERT o UPDATE.' },
    { tema:'UF7', p:'¿Qué son las relaciones Eloquent hasMany/belongsTo?', ops:['Métodos para contar registros en las relaciones','Definición de relaciones uno-a-muchos entre modelos (un usuario tiene muchos posts; un post pertenece a un usuario)','Tipos de índices en la base de datos','Métodos de validación de modelos'], r:1, e:'hasMany en User: un usuario tiene muchos Post. belongsTo en Post: un post pertenece a un User. Eloquent genera automáticamente el JOIN correcto.' },
    { tema:'UF7', p:'¿Qué es el problema N+1 en ORMs y cómo se resuelve en Laravel?', ops:['Un error de PHP al acceder a arrays','Ejecutar N consultas adicionales para cargar relaciones de N registros. Se resuelve con eager loading (::with()).','Un límite de conexiones simultáneas a la BD','Un bug de rendimiento en Laravel 7 o anterior'], r:1, e:'N+1: si cargas 100 usuarios y accedes a sus posts, sin eager loading = 101 consultas. Con User::with(\'posts\')->get() = solo 2 consultas. Crítico para el rendimiento.' },
    { tema:'UF7', p:'¿Qué hace php artisan en Laravel?', ops:['Instala dependencias Composer','La CLI de Laravel para ejecutar comandos: migrate, db:seed, make:controller, serve, tinker, etc.','Compila los archivos Blade a PHP','Gestiona los logs de la aplicación'], r:1, e:'Artisan es la interfaz de línea de comandos de Laravel. Comandos clave: php artisan serve (server local), migrate (migraciones), make:model, make:controller, db:seed.' },
    { tema:'UF7', p:'¿Qué es Laravel Sanctum?', ops:['Un sistema de plantillas seguras','Un paquete para autenticación de SPA y apps móviles mediante tokens de API y cookies de sesión','El sistema de encriptación de contraseñas de Laravel','Un middleware de seguridad CORS'], r:1, e:'Sanctum proporciona autenticación ligera para SPA (session cookie), APIs móviles (API tokens en BD). Alternativa más simple a Passport para la mayoría de casos.' },
    { tema:'UF7', p:'¿Qué es el helper dd() en Laravel?', ops:['Database Driver — clase para conexiones a BD','Dump and Die — muestra el valor de una variable formateado y detiene la ejecución, útil para depuración','Un comando Artisan para depurar migraciones','Un tipo de directiva Blade'], r:1, e:'dd($variable) (Dump and Die) muestra el valor formateado y detiene la ejecución. dump() muestra sin detener. Útil para depuración rápida.' },
    { tema:'UF7', p:'¿Qué son las policies en Laravel?', ops:['Archivos de configuración de rutas','Clases que centralizan la lógica de autorización: si un usuario puede realizar una acción sobre un recurso','Reglas de validación de formularios','Middlewares de autenticación'], r:1, e:'Las policies centralizan la autorización: PostPolicy con métodos como update($user, $post) que devuelven true/false. En el controlador: $this->authorize(\'update\', $post).' },
    { tema:'UF7', p:'¿Qué es el archivo .env en Laravel?', ops:['El archivo de configuración de Apache para Laravel','El archivo de variables de entorno que almacena configuración sensible (BD, claves, APIs) fuera del código fuente','Un archivo de plantillas de configuración','El log principal de la aplicación'], r:1, e:'.env almacena configuración sensible por entorno: DB_DATABASE, APP_KEY, MAIL_HOST, API_KEY... No debe subirse al repositorio (está en .gitignore).' },
    { tema:'UF7', p:'¿Qué es la caché en Laravel y para qué sirve?', ops:['El sistema de sesiones de usuario','Un sistema para almacenar temporalmente resultados de consultas costosas, reduciendo la carga en la BD','El sistema de logs de Laravel','Un sistema de compresión de assets'], r:1, e:'Laravel Cache (drivers: Redis, Memcached, file) almacena resultados costosos. Cache::remember(\'usuarios\', 3600, fn() => User::all()) devuelve la caché si existe o ejecuta el callback.' },
    { tema:'UF7', p:'¿Qué son las jobs y queues en Laravel?', ops:['Tareas programadas con cron','Clases que encapsulan tareas pesadas para ejecutarlas de forma asíncrona en segundo plano','Logs de peticiones HTTP','Middlewares de autenticación asíncrona'], r:1, e:'Las queues permiten aplazar tareas pesadas (envío de emails, procesamiento de imágenes). El worker (php artisan queue:work) las procesa en background.' },
    { tema:'UF7', p:'¿Qué son los Resource Controllers en Laravel y qué métodos incluyen?', ops:['Controladores que solo tienen el método index()','Controladores generados con --resource que incluyen los 7 métodos CRUD estándar: index, create, store, show, edit, update, destroy','Controladores para gestionar archivos en el servidor','Controladores de rutas de API únicamente'], r:1, e:'php artisan make:controller ProductoController --resource genera los 7 métodos: index (lista), create (form), store (guardar), show (detalle), edit (form edición), update (actualizar), destroy (borrar).' },
    { tema:'UF7', p:'¿Qué comando Artisan genera un nuevo modelo con su migración y controlador en Laravel?', ops:['php artisan create:model Producto','php artisan make:model Producto -mcr','php artisan generate Producto --all','php artisan scaffold Producto'], r:1, e:'php artisan make:model Producto -mcr crea el modelo, la migración, el controlador y el seeder de recursos REST en un solo comando.' },
    { tema:'UF7', p:'¿Qué es el patrón Observer en Laravel?', ops:['Un patrón para monitorizar el rendimiento de la BD','Una clase que escucha eventos del ciclo de vida de los modelos Eloquent (created, updated, deleted) para ejecutar lógica adicional','Un sistema de notificaciones push','Un middleware de logging'], r:1, e:'Los Observers de Eloquent agrupan los event listeners de un modelo. ProductoObserver con métodos created(), updated(), deleted(). Se registra con Producto::observe(ProductoObserver::class).' },
    { tema:'UF7', p:'¿Qué es la inyección de dependencias en los controladores de Laravel?', ops:['Pasar datos SQL directamente a las consultas','Declarar tipos de clases en el constructor o métodos del controlador para que el Service Container las instancie e inyecte automáticamente','Inyectar JavaScript en las vistas Blade','Importar clases con use en PHP'], r:1, e:'Al declarar function store(Request $request, ProductoService $service), Laravel instancia ProductoService automáticamente. No hace falta new ProductoService(). Facilita el testing.' },
  ],

  // ─────────────────────────────────────────────────────────
  // UF8 — APLICACIONES HÍBRIDAS / MASHUP
  // ─────────────────────────────────────────────────────────
  UF8: [
    { tema:'UF8', p:'¿Cuál es la característica más importante de las tecnologías para apps híbridas?', ops:['Todas las tecnologías web son inadecuadas para apps híbridas','Lo ideal es siempre una app nativa','Desarrollar con el mínimo código posible adaptable a cualquier plataforma con buen rendimiento','El rendimiento siempre es inferior al nativo'], r:2, e:'Las tecnologías para apps híbridas (React Native, Flutter, Ionic...) permiten un único código base que se adapta a iOS, Android y web.' },
    { tema:'UF8', p:'Al utilizar servicios de terceros como Google, AWS o Azure...', ops:['Todos los servicios son gratuitos siempre','Siempre son de pago independientemente de las peticiones','En la mayoría de los casos necesitamos registrarnos y obtener una API key','No requieren ningún tipo de autenticación'], r:2, e:'Los servicios cloud de terceros casi siempre requieren registro y una API key para identificar al consumidor y controlar el uso.' },
    { tema:'UF8', p:'¿Qué debe cumplir una aplicación web para considerarse híbrida o mashup?', ops:['Solo integrar un vídeo de YouTube ya la hace híbrida','Acceder a una base de datos propia exclusivamente','Nuestra app debe acceder y procesar datos que proporcione un servicio de terceros','Usar JavaScript en el frontend'], r:2, e:'Un mashup combina datos o funcionalidades de múltiples fuentes externas (APIs, feeds) para crear un nuevo servicio o interfaz.' },
    { tema:'UF8', p:'¿Dónde puede ejecutarse un mashup?', ops:['Solo en el cliente','Solo en el servidor','En el cliente o en el servidor','Solo en servidores cloud'], r:2, e:'Un mashup puede ejecutarse tanto en el cliente (JavaScript del navegador) como en el servidor (PHP, Node.js...) o en ambos.' },
    { tema:'UF8', p:'Para manejar comunicaciones HTTP simples en PHP usamos...', ops:['curl','Ninguna de las anteriores','file_get_contents()','http_request()'], r:2, e:'file_get_contents() puede hacer peticiones HTTP simples (GET). Para peticiones más complejas (POST, headers, HTTPS) se usa cURL.' },
    { tema:'UF8', p:'¿Qué devuelve json_decode() en PHP?', ops:['Un array','Una cadena de texto','Un objeto','Un recurso PHP'], r:2, e:'json_decode() devuelve un objeto stdClass por defecto. Con el segundo parámetro a true devuelve un array asociativo.' },
    { tema:'UF8', p:'¿Cuál es la gran ventaja de las aplicaciones híbridas respecto a las nativas?', ops:['Rendimiento muy superior','No permite reutilización de código','El desarrollo es más sencillo y económico frente a los desarrollos nativos','Mayor acceso a APIs del dispositivo'], r:2, e:'Un único equipo y codebase para múltiples plataformas reduce drásticamente el coste y tiempo de desarrollo.' },
    { tema:'UF8', p:'RSS y Atom son...', ops:['Dos proveedores de contenidos','Solo una estructura de fuentes web','Formatos de fuentes web y protocolos de sindicación web','Lenguajes de marcado para apps híbridas'], r:2, e:'RSS y Atom son formatos XML estándar para sindicación de contenidos web, que permiten suscribirse a actualizaciones de sitios.' },
    { tema:'UF8', p:'¿Qué etiquetas son obligatorias dentro del elemento raíz de un documento RSS?', ops:['No necesita etiquetas obligatorias','title, link y language','title, link y description','title, description e image'], r:2, e:'Un canal RSS válido debe tener obligatoriamente: title, link y description dentro del elemento channel.' },
    { tema:'UF8', p:'¿Qué función PHP se debe usar para acceder a servicios web mediante HTTPS y FTPS?', ops:['file_get_contents()','file_get_contents() o cURL indistintamente','cURL','http_get()'], r:2, e:'cURL soporta HTTPS (SSL/TLS) y FTPS. file_get_contents() puede hacer HTTPS si allow_url_fopen=On, pero cURL es más robusto.' },
    { tema:'UF8', p:'¿Qué son los protocolos de sindicación web?', ops:['Protocolos para intercambiar contenidos en formato texto únicamente','Los mismos que los protocolos web estándar','Protocolos para poner contenidos web a disposición de otros sitios o aplicaciones','Protocolos de seguridad para APIs'], r:2, e:'La sindicación web permite que los contenidos de un sitio estén disponibles para ser consumidos por otros sitios o aplicaciones (RSS, Atom).' },
    { tema:'UF8', p:'Las aplicaciones que utilizan técnicas de ingeniería inversa para extraer datos de webs son conocidas como...', ops:['Mashup','RSS','Web scraping','API consumers'], r:2, e:'Web scraping extrae datos de páginas web analizando el HTML, sin usar una API oficial. Es ingeniería inversa de la interfaz visual.' },
    { tema:'UF8', p:'¿Cuáles son los tipos de fuentes de información más habituales en una app web híbrida?', ops:['Solo fuentes públicas en XML','Solo APIs que devuelven JSON','Servicios web con XML/JSON, APIs de terceros y fuentes RSS o Atom','Solo APIs REST con autenticación'], r:2, e:'Una app híbrida puede consumir: APIs REST (JSON/XML), feeds RSS/Atom, APIs de terceros (Google Maps...), scraping, etc.' },
    { tema:'UF8', p:'¿Qué significa OAuth2 en el contexto de las aplicaciones híbridas?', ops:['Un formato de datos alternativo a JSON','Un protocolo de autorización que permite a aplicaciones acceder a recursos de un usuario en otro servicio sin compartir contraseñas','Un tipo de base de datos para mashups','Un protocolo de sindicación web'], r:1, e:'OAuth2 es el protocolo estándar de autorización. Permite que una app acceda a recursos de un servicio externo (Google, Twitter...) con permiso del usuario, sin exponer su contraseña.' },
    { tema:'UF8', p:'¿Qué son JWT en el contexto de las aplicaciones web?', ops:['Java Web Tools','JSON Web Tokens: tokens compactos y autónomos para transmitir información entre partes de forma segura','JavaScript Widget Templates','Java Wrapper Types'], r:1, e:'JWT (JSON Web Tokens) son tokens firmados que contienen información (claims) y se usan para autenticación stateless en APIs y mashups.' },
    { tema:'UF8', p:'¿Cuál es la arquitectura de un mashup según el temario?', ops:['Una sola capa: el navegador','Dos capas: cliente y servidor','Tres partes: la fuente de datos, el sitio que alberga el mashup y el navegador del cliente','Cuatro capas: datos, lógica, presentación y red'], r:2, e:'Todo mashup tiene: (1) fuente de datos externa, (2) el sitio que aloja y procesa el mashup, y (3) el navegador del cliente donde se renderiza.' },
    { tema:'UF8', p:'¿Cuál es el mashup más conocido que inspiró a muchas empresas a abrir sus APIs?', ops:['Twitter Maps','Facebook Places','Google Maps','Amazon Product Finder'], r:2, e:'Google Maps es el mashup más popular y ha generado millones de aplicaciones. Google abrió su API para que desarrolladores de todo el mundo crearan servicios sobre ella.' },
    { tema:'UF8', p:'¿Qué técnica se usa cuando un proveedor de datos no tiene API oficial y hay que extraer datos de su HTML?', ops:['API Polling','Web Scraping o Screen Scraping','RSS parsing','OAuth scraping'], r:1, e:'Screen scraping / web scraping extrae información directamente del HTML de la página, traduciendo el contenido a un formato utilizable.' },
    { tema:'UF8', p:'¿Qué significa RIA en el contexto de los mashups?', ops:['Remote Interface Application','Rich Internet Application: aplicación web enriquecida e interactiva, similar a una app de escritorio','Reactive Interface Architecture','Real-time Interface API'], r:1, e:'RIA = Rich Internet Application. Los mashups que usan AJAX son RIA: ofrecen interactividad sin recargar la página, mejorando la experiencia.' },
    { tema:'UF8', p:'¿Qué tipo de mashup combina datos de localización con mapas para visualizar información geográfica?', ops:['Mashup de fotos','Mashup de noticias','Mashup de mapas','Mashup de compras'], r:2, e:'Los mashups de mapas (ej: Google Maps + datos de negocio) son los más populares. Aprovechan la comprensión visual de la información geolocalizada.' },
    { tema:'UF8', p:'¿Qué es Nuxt.js y para qué se usa con Vue?', ops:['Un servidor web ligero para Node.js','Un framework basado en Vue.js para crear aplicaciones con SSR (renderizado en servidor) y generación de sitios estáticos','Una librería de componentes UI para Vue','Un sistema de testing para Vue.js'], r:1, e:'Nuxt.js añade SSR (Server-Side Rendering) y SSG (Static Site Generation) a Vue. SSR: el servidor genera el HTML inicial (mejor SEO, carga inicial más rápida).' },
    { tema:'UF8', p:'¿Qué es el renderizado en el servidor (SSR) y por qué mejora el SEO?', ops:['El servidor procesa CSS y lo envía al cliente','El servidor genera el HTML completo antes de enviarlo al cliente, haciendo el contenido indexable por buscadores desde el primer momento','Una técnica de compresión de respuestas HTTP','El procesamiento de JavaScript en el servidor con Node.js'], r:1, e:'Con SSR el servidor envía HTML ya renderizado. Los crawlers de Google indexan el contenido inmediatamente. Las SPA tradicionales envían HTML vacío y el contenido lo genera JavaScript.' },
    { tema:'UF8', p:'¿Qué es Inertia.js en el contexto de Laravel + Vue?', ops:['Un sistema de testing E2E','Una librería que conecta Laravel (backend) con Vue/React (frontend) sin necesidad de API REST, compartiendo datos como props','Un paquete para generación de PDFs','Un sistema de autenticación para SPAs'], r:1, e:'Inertia.js permite usar Vue/React como sistema de vistas de Laravel sin construir una API. El controlador devuelve componentes Vue con sus props.' },
    { tema:'UF8', p:'¿Qué es Livewire en Laravel?', ops:['Un paquete para animaciones CSS en Laravel','Un framework para crear componentes dinámicos con PHP sin escribir JavaScript, usando AJAX transparente','Un sistema de websockets para Laravel','Una librería de tests para componentes Blade'], r:1, e:'Livewire permite crear componentes interactivos con PHP puro. Cada interacción hace una petición AJAX al servidor que devuelve el HTML actualizado.' },
    { tema:'UF8', p:'¿Qué son los WebSockets y cuándo usarlos en lugar de HTTP?', ops:['Un protocolo de transferencia de archivos entre servidores','Un protocolo de comunicación bidireccional y persistente, ideal para tiempo real (chat, notificaciones, juegos)','Un sistema de caché de respuestas HTTP','Un protocolo de autenticación en tiempo real'], r:1, e:'WebSockets mantienen una conexión bidireccional abierta. El servidor puede enviar datos al cliente sin que este lo solicite. Ideal para: chat, notificaciones push, dashboards en tiempo real.' },
    { tema:'UF8', p:'¿Qué es Vite y para qué se usa en proyectos Laravel modernos?', ops:['Un servidor web ligero para PHP','Un bundler y servidor de desarrollo ultra-rápido que reemplaza a Webpack en el ecosistema Laravel + Vue/React','Un gestor de paquetes npm alternativo','Un sistema de despliegue automático'], r:1, e:'Vite ofrece Hot Module Replacement (HMR) instantáneo en desarrollo y builds de producción optimizados. Laravel 9+ usa Vite por defecto con el paquete laravel-vite-plugin.' },
    { tema:'UF8', p:'¿Qué es PWA (Progressive Web App)?', ops:['Un tipo especial de aplicación nativa iOS','Una web que funciona como app nativa: instalable, funciona offline (Service Worker + caché), recibe notificaciones push','Un framework JavaScript alternativo a Vue','Un tipo de SPA con autenticación OAuth'], r:1, e:'Una PWA usa Service Workers para funcionar offline, Web App Manifest para ser instalable y Push Notifications. Sin pasar por tienda de apps.' },
    { tema:'UF8', p:'¿Qué es Capacitor/Ionic para apps híbridas?', ops:['Un servidor web para apps móviles','Un framework que empaqueta aplicaciones web (Vue, React) como apps nativas iOS y Android, con acceso a APIs del dispositivo','Una librería CSS para diseño móvil','Un sistema de testing para apps móviles'], r:1, e:'Capacitor envuelve una web en una WebView nativa. La app se distribuye en App Store/Play Store. Plugins de Capacitor dan acceso a cámara, GPS, biometría, etc.' },
    { tema:'UF8', p:'¿Qué es el principio DRY en programación?', ops:['Debug-Run-Yield: ciclo de desarrollo iterativo','Don\'t Repeat Yourself: cada pieza de conocimiento debe tener una única representación en el sistema','Dynamic-Runtime-Yield: patrón de ejecución diferida','Direct-Request-Yield: patrón de peticiones directas'], r:1, e:'DRY significa no duplicar código. Si la misma lógica aparece en dos sitios, un cambio requiere actualizarlos ambos. Se resuelve con funciones, clases, traits o herencia.' },
    { tema:'UF8', p:'¿Qué es SOLID en programación orientada a objetos?', ops:['Un acrónimo de cinco principios de diseño OOP: Single Responsibility, Open/Closed, Liskov Substitution, Interface Segregation, Dependency Inversion','Un framework PHP alternativo a Laravel','Un patrón de arquitectura de microservicios','Un sistema de testing de código PHP'], r:0, e:'SOLID: S-Single Responsibility, O-Open/Closed, L-Liskov Substitution, I-Interface Segregation, D-Dependency Inversion. Guía para código mantenible y extensible.' },
    { tema:'UF8', p:'¿Qué es AJAX en el contexto de aplicaciones web?', ops:['Un framework JavaScript alternativo a Vue','Una técnica que permite hacer peticiones HTTP asíncronas desde JavaScript sin recargar la página, actualizando partes del DOM','Un protocolo de comunicación entre servidores','Un sistema de compresión de respuestas HTTP'], r:1, e:'AJAX permite actualizar partes de la página sin recargar. Hoy se usa fetch() o Axios. Es la base de las SPAs y los mashups.' },
    { tema:'UF8', p:'¿Qué es una SPA (Single Page Application)?', ops:['Una web de una sola página sin interactividad','Una aplicación web donde el navegador carga el HTML una vez y actualiza el contenido dinámicamente sin recargas completas, usando JavaScript','Una web optimizada solo para móviles','Una aplicación PHP sin base de datos'], r:1, e:'Las SPAs (Angular, React, Vue) cargan el HTML/JS una vez. La navegación actualiza el DOM con JavaScript. Las peticiones al servidor son solo datos (JSON).' },
    { tema:'UF8', p:'¿Qué es fetch() en JavaScript y cómo se usa para consumir una API?', ops:['Una función PHP para leer archivos','La API moderna de JavaScript para hacer peticiones HTTP asíncronas, devolviendo una Promise','Un método de Vue para cargar datos','Un plugin de jQuery'], r:1, e:'fetch(url).then(r => r.json()).then(data => ...) es la alternativa moderna a XMLHttpRequest. Soporta GET, POST, headers personalizados y manejo de errores con async/await.' },
    { tema:'UF8', p:'¿Qué es Axios y por qué se usa frente a fetch nativo?', ops:['Un framework de backend JavaScript','Una librería HTTP para el navegador y Node.js que simplifica las peticiones con interceptores, transformación automática de JSON y mejor manejo de errores','Un bundler de módulos JavaScript','Un sistema de gestión de estado'], r:1, e:'Axios convierte automáticamente JSON, tiene interceptors (para añadir tokens a todas las peticiones) y manejo de errores más claro. Vue y React lo usan ampliamente.' },
    { tema:'UF8', p:'¿Qué es el CORS y por qué afecta a las apps que consumen APIs externas?', ops:['Un tipo de certificado SSL','Cross-Origin Resource Sharing: política del navegador que bloquea peticiones fetch a dominios distintos al de la web que las hace, a menos que el servidor lo permita expresamente','Un protocolo de autenticación entre dominios','Un sistema de caché de respuestas HTTP'], r:1, e:'Si tu frontend hace fetch a una API en otro dominio, el navegador bloquea la respuesta. El servidor debe enviar Access-Control-Allow-Origin con el dominio permitido.' },
  ],

  // ─────────────────────────────────────────────────────────
  // UF9 — SERVIDORES EN LA NUBE
  // ─────────────────────────────────────────────────────────
  UF9: [
    { tema:'UF9', p:'¿Qué servicio de Azure se encarga de realizar el despliegue de aplicaciones?', ops:['Resource Manager','CLI','DevOps','App Service'], r:2, e:'Azure DevOps proporciona pipelines CI/CD para automatizar el despliegue de aplicaciones en los servicios de Azure.' },
    { tema:'UF9', p:'¿Qué servicios de AWS ofrecen procesamiento de Big Data?', ops:['IoT HUB, Event HUB','EMR, Data Pipeline, Glue','Ninguna de las anteriores','Redshift, DynamoDB, Aurora'], r:1, e:'EMR (Elastic MapReduce), Data Pipeline y Glue son los servicios de AWS especializados en procesamiento de Big Data.' },
    { tema:'UF9', p:'En el ámbito empresarial, ¿cómo se elige el proveedor cloud?', ops:['Importa poco, los servicios son idénticos','Los estándares están en normas IEEE','Según coste económico, fiabilidad, integración con lo preexistente, etc.','Siempre se elige AWS por ser el primero'], r:2, e:'La elección del proveedor cloud depende de múltiples factores: coste, SLA, compatibilidad con tecnologías existentes, soporte, etc.' },
    { tema:'UF9', p:'¿Qué clase de servicio ofrece AWS Step Functions?', ops:['Control de acceso','Orquestación de flujos de trabajo','Almacenamiento de datos','Computación serverless'], r:1, e:'Step Functions es un servicio de orquestación que coordina múltiples servicios AWS en flujos de trabajo visuales y secuenciales.' },
    { tema:'UF9', p:'En una arquitectura LAMP en la nube AWS, ¿cómo se comparte el código entre servidores?', ops:['Las peticiones estáticas las atiende un grupo de servidores en reverse proxy','Las peticiones dinámicas las atiende la CDN Cloudfront','El código se comparte desde un repositorio común, normalmente por NFS','Cada servidor tiene su propia copia independiente del código'], r:2, e:'En arquitecturas escaladas, el código se centraliza en NFS o S3 y se monta en todos los servidores de aplicación para garantizar consistencia.' },
    { tema:'UF9', p:'Respecto a los tipos de escalado, ¿cuál es más complejo?', ops:['El escalado vertical es más complejo','El escalado horizontal es mucho más complejo de implementar','Ambos tienen la misma complejidad','El serverless no requiere escalado'], r:1, e:'El escalado horizontal requiere que la aplicación sea stateless, usar sesiones externas, compartir almacenamiento, etc. El vertical es más simple.' },
    { tema:'UF9', p:'¿Qué ofrece el servicio AWS Cloud9?', ops:['Un servicio de integración continua','Un servicio de control de versiones','Un entorno de desarrollo integrado (IDE) en la nube','Un servicio de base de datos gestionada'], r:2, e:'Cloud9 es un IDE en la nube que permite editar, ejecutar y depurar código directamente desde el navegador, sin instalar nada localmente.' },
    { tema:'UF9', p:'¿Qué servicio de AWS se encarga de desplegar la aplicación (CD)?', ops:['AWS CodeCommit','AWS CodeBuild','AWS CodeDeploy','AWS CodePipeline'], r:2, e:'CodeDeploy automatiza el despliegue de aplicaciones a EC2, Lambda, ECS u on-premise. CodeBuild compila y CodeCommit es el repositorio.' },
    { tema:'UF9', p:'¿Qué servicio de Azure es equivalente a AWS Step Functions?', ops:['Azure Debug Functions','Azure no tiene esa funcionalidad','Azure Logic Apps','Azure Functions'], r:2, e:'Azure Logic Apps es el servicio de orquestación de flujos de trabajo de Azure, equivalente a AWS Step Functions.' },
    { tema:'UF9', p:'¿En qué se basa el servicio de almacenamiento S3 de AWS?', ops:['Máquinas Virtuales','Bases de datos relacionales','Contenedores o cubos (buckets) de objetos','Sistemas de archivos NFS'], r:2, e:'S3 usa un modelo de almacenamiento basado en objetos agrupados en buckets. Cada objeto tiene una clave única, datos y metadatos.' },
    { tema:'UF9', p:'¿Cuál es la característica fundamental de la arquitectura de microservicios?', ops:['Utiliza un modelo de componentes acoplados','Utiliza un modelo de capas lógicas único','Divide la aplicación en componentes desplegados por separado que se comunican a través de una interfaz común','Requiere siempre Kubernetes para funcionar'], r:2, e:'Los microservicios son unidades autónomas con su propia estructura de capas, desplegables independientemente y comunicadas por APIs.' },
    { tema:'UF9', p:'¿Qué es AWS EC2?', ops:['Un servicio de almacenamiento de objetos','Elastic Compute Cloud: servicio de virtualización de máquinas de AWS, pionero del cloud computing','Un servicio de base de datos gestionada','Un servicio de CDN'], r:1, e:'EC2 (Elastic Compute Cloud) lanzado en 2006 fue el servicio que popularizó el cloud computing, ofreciendo máquinas virtuales bajo demanda.' },
    { tema:'UF9', p:'¿Qué es el escalado vertical en la nube?', ops:['Añadir más instancias iguales al sistema','Aumentar los recursos (CPU, RAM) de una instancia sin añadir nuevas máquinas','Distribuir la carga entre múltiples servidores','Replicar la aplicación en múltiples regiones'], r:1, e:'Escalado vertical (scale up): aumentar la capacidad de una sola instancia. Tiene límite máximo y crea punto único de fallo.' },
    { tema:'UF9', p:'¿Qué es serverless?', ops:['Que la app no necesita código de servidor','Un servidor que no consume energía','Un modelo donde el proveedor cloud gestiona la infraestructura; el desarrollador solo sube funciones que se ejecutan bajo demanda','Una arquitectura donde todo el código corre en el cliente'], r:2, e:'Serverless: el desarrollador no gestiona servidores. Solo despliega funciones que se ejecutan bajo demanda y escalan automáticamente. Se paga por ejecución.' },
    { tema:'UF9', p:'¿Qué es Kubernetes?', ops:['Un sistema de almacenamiento en la nube','Un sistema de orquestación de contenedores que automatiza despliegue, escalado y gestión','Un lenguaje para la nube','Una base de datos NoSQL para microservicios'], r:1, e:'Kubernetes (k8s) fue creado por Google y es el estándar de facto para orquestar contenedores Docker en producción.' },
    { tema:'UF9', p:'¿Qué es la integración continua (CI)?', ops:['Integrar manualmente el código una vez al mes','Una práctica donde los desarrolladores integran código frecuentemente, disparando automáticamente tests y verificaciones','Un tipo de control de versiones','Un sistema de despliegue manual'], r:1, e:'CI: los desarrolladores integran cambios múltiples veces al día. Cada push dispara automáticamente un pipeline de build, tests y análisis.' },
    { tema:'UF9', p:'¿Qué es un VPS (Virtual Private Server)?', ops:['Un servidor físico dedicado exclusivamente','Un servidor virtual que simula ser un servidor dedicado, con recursos garantizados, dentro de un servidor físico compartido','Una red privada virtual','Un servicio de almacenamiento virtual'], r:1, e:'VPS: partición virtual de un servidor físico con recursos garantizados y acceso root. Más barato que un dedicado, más potente que el hosting compartido.' },
    { tema:'UF9', p:'¿Qué servicio AWS es un PaaS que despliega aplicaciones en múltiples lenguajes sin gestionar la infraestructura?', ops:['EC2','Lightsail','Elastic Beanstalk','Lambda'], r:2, e:'AWS Elastic Beanstalk es un PaaS: el desarrollador sube la aplicación (PHP, Node.js, Java...) y AWS gestiona la infraestructura (EC2, balanceador, escalado).' },
    { tema:'UF9', p:'¿Qué es una CDN (Content Delivery Network)?', ops:['Una red de bases de datos distribuidas','Un servicio que ofrece contenidos estáticos desde ubicaciones geográficamente más cercanas al usuario','Un sistema de copias de seguridad automáticas','Un protocolo de comunicación entre microservicios'], r:1, e:'Una CDN distribuye contenidos estáticos (imágenes, CSS, JS) desde puntos de presencia (PoP) cercanos al usuario, reduciendo latencia y mejorando la velocidad.' },
    { tema:'UF9', p:'¿Qué diferencia hay entre ECS y EKS en AWS?', ops:['ECS es para máquinas virtuales, EKS para contenedores','ECS usa estándares propios de AWS con Docker; EKS usa Kubernetes (estándar open-source de la industria)','ECS es más caro y complejo que EKS','No hay diferencia práctica'], r:1, e:'ECS orquesta contenedores Docker con tecnología propia de AWS. EKS usa Kubernetes (open-source, creado por Google), más portátil pero más complejo.' },
    { tema:'UF9', p:'¿Qué ventaja principal ofrece la arquitectura de microservicios frente a la arquitectura monolítica?', ops:['Es más sencilla de desarrollar inicialmente','Permite desplegar, escalar y actualizar cada servicio independientemente sin afectar al resto','Requiere menos infraestructura','Siempre tiene mejor rendimiento que un monolito'], r:1, e:'Los microservicios permiten escalar, actualizar y desplegar componentes individuales de forma independiente, mejorando la resiliencia y la agilidad.' },
    { tema:'UF9', p:'¿En qué año comenzó AWS a ofrecer sus servicios cloud pioneros (EC2 y S3)?', ops:['2000','2003','2006','2010'], r:2, e:'En 2006 AWS lanzó EC2 (máquinas virtuales) y S3 (almacenamiento de objetos), los servicios pioneros del cloud computing moderno.' },
    { tema:'UF9', p:'¿Qué es AWS Lambda?', ops:['Un servicio de contenedores Docker','Un servicio de bases de datos NoSQL','Un servicio serverless que ejecuta funciones bajo demanda sin gestionar servidores','Un servicio de CDN'], r:2, e:'AWS Lambda es el servicio serverless de AWS. El código se sube como función y se ejecuta solo cuando hay un evento (petición HTTP, mensaje en cola...). Se paga por ejecución.' },
    { tema:'UF9', p:'¿Qué es AWS Fargate?', ops:['Un servicio de almacenamiento de objetos','Un servicio serverless para ejecutar contenedores sin gestionar la infraestructura subyacente','Un balanceador de carga','Un servicio de DNS gestionado'], r:1, e:'Fargate es serverless para contenedores: permite ejecutar contenedores Docker sin provisionar ni gestionar servidores. Complementa a ECS y EKS.' },
    { tema:'UF9', p:'¿Qué es DevOps y cómo se relaciona con el despliegue de aplicaciones web?', ops:['Un lenguaje de programación para scripts de despliegue','Una metodología que integra desarrollo y operaciones para automatizar el ciclo de vida del software mediante CI/CD, IaC y monitorización','Un tipo de servidor virtualizado','Un protocolo de comunicación entre frontend y backend'], r:1, e:'DevOps elimina la barrera entre developers y operaciones. CI/CD automatiza tests y despliegues. IaC (Terraform, Ansible) define la infraestructura como código.' },
    { tema:'UF9', p:'¿Qué es Terraform?', ops:['Un framework PHP para microservicios','Una herramienta de Infraestructura como Código (IaC) que provisiona y gestiona recursos cloud (AWS, Azure, GCP) con archivos declarativos','Un sistema de orquestación de contenedores alternativo a Kubernetes','Un servicio de monitorización cloud'], r:1, e:'Terraform usa archivos HCL declarativos para definir la infraestructura: VMs, bases de datos, redes, DNS. terraform plan muestra los cambios; terraform apply los ejecuta.' },
    { tema:'UF9', p:'¿Qué es un load balancer (balanceador de carga) y para qué sirve?', ops:['Un sistema de caché para bases de datos','Un componente que distribuye el tráfico entrante entre múltiples instancias del servidor para mejorar disponibilidad y rendimiento','Un firewall de aplicaciones web','Un sistema de monitorización de red'], r:1, e:'El balanceador de carga distribuye las peticiones HTTP entre varios servidores. Si uno cae, las peticiones van a los otros. AWS ALB, NGINX, HAProxy son balanceadores populares.' },
    { tema:'UF9', p:'¿Qué es el despliegue azul-verde (Blue-Green Deployment)?', ops:['Una estrategia de branding para aplicaciones','Una técnica de despliegue que mantiene dos entornos idénticos (azul=producción, verde=nueva versión) y conmuta el tráfico instantáneamente','Un sistema de control de versiones para bases de datos','Una técnica de A/B testing de interfaces'], r:1, e:'Blue-Green: el entorno azul sirve producción actual; el verde se actualiza con la nueva versión. Cuando está validado, el balanceador conmuta el tráfico. Rollback instantáneo: volver a apuntar al azul.' },
    { tema:'UF9', p:'¿Qué es el despliegue canario (Canary Release)?', ops:['Un despliegue solo en servidores europeos','Enviar una pequeña fracción del tráfico (1-5%) a la nueva versión para validar en producción real antes del despliegue completo','Un sistema de alerta temprana de fallos','Un tipo de prueba de carga'], r:1, e:'Canary Release: la nueva versión recibe solo el 1-5% del tráfico. Si las métricas son buenas, se aumenta gradualmente hasta el 100%. Detecta problemas antes de afectar a todos.' },
    { tema:'UF9', p:'¿Qué es GitHub Actions y para qué se usa en CI/CD?', ops:['Un sistema de almacenamiento de código fuente','Una plataforma de automatización integrada en GitHub que ejecuta workflows (tests, builds, deploys) al hacer push o pull request','Un gestor de paquetes alternativo a npm','Un sistema de monitorización de aplicaciones'], r:1, e:'GitHub Actions define workflows en .github/workflows/deploy.yml. Al hacer push, ejecuta automáticamente tests, construye la imagen Docker y despliega en el servidor.' },
    { tema:'UF9', p:'¿Qué es un contenedor Docker y en qué se diferencia de una máquina virtual?', ops:['Son tecnologías idénticas','Los contenedores comparten el kernel del host y son más ligeros y rápidos; las VMs incluyen un SO completo y tienen mayor aislamiento pero más overhead','Los contenedores son siempre más seguros que las VMs','Las VMs son más rápidas de iniciar que los contenedores'], r:1, e:'Docker: los contenedores comparten el kernel del host, se inician en segundos y consumen MB. Las VMs incluyen un SO completo (GB) y arrancan en minutos.' },
    { tema:'UF9', p:'¿Qué es el archivo docker-compose.yml?', ops:['El Dockerfile principal de la aplicación','Un archivo YAML que define y configura múltiples contenedores (PHP, MySQL, Nginx) como un stack, levantado con docker-compose up','Un archivo de variables de entorno','Un script de despliegue en el servidor'], r:1, e:'docker-compose.yml define servicios, redes y volúmenes. services: {app: {image: php:8.2}, db: {image: mysql:8}}. docker-compose up levanta todo el stack con un solo comando.' },
    { tema:'UF9', p:'¿Qué es el SLA (Service Level Agreement) en servicios cloud?', ops:['Un lenguaje de scripting de administración de servidores','Un acuerdo formal entre el proveedor cloud y el cliente que garantiza un nivel mínimo de disponibilidad, rendimiento y soporte','Un protocolo de autenticación entre servicios cloud','Un sistema de logs de disponibilidad'], r:1, e:'El SLA define el uptime garantizado: 99.9% = máx 8.7h downtime/año, 99.99% = máx 52min/año. Incluye penalizaciones si no se cumplen.' },
    { tema:'UF9', p:'¿Qué es la observabilidad (observability) en sistemas cloud?', ops:['La capacidad de ver el código fuente de un sistema','La capacidad de entender el estado interno de un sistema a través de sus outputs externos: logs, métricas y trazas distribuidas','Un tipo de test de rendimiento','Un sistema de monitorización de red básico'], r:1, e:'Los tres pilares: Logs (eventos), Métricas (CPU, latencia, errores) y Trazas distribuidas (seguimiento de una petición a través de microservicios). Herramientas: OpenTelemetry, Datadog.' },
  ],

};
